type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  input: unknown,
  prefix: string = "",
  result: FlatObject = {},
  depth: number = 0
): FlatObject {
  const MAX_DEPTH = 100;

  if (depth > MAX_DEPTH) {
    throw new RangeError(
      `flattenObject: maximum nesting depth of ${MAX_DEPTH} exceeded at key "${prefix}". Possible circular reference or excessively deep structure.`
    );
  }

  if (input === null || input === undefined) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (typeof input !== "object" || Array.isArray(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive | unknown[];
    }
    return result;
  }

  const obj = input as Record<string, unknown>;
  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix !== "") {
      result[prefix] = {} as unknown as Primitive;
    }
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) {
      continue;
    }

    if (key === "") {
      const compositeKey = prefix !== "" ? `${prefix}.` : ".";
      const value = obj[key];
      if (
        value !== null &&
        typeof value === "object" &&
        !Array.isArray(value)
      ) {
        flattenObject(value, compositeKey, result, depth + 1);
      } else {
        result[compositeKey] = value as Primitive | unknown[];
      }
      continue;
    }

    const compositeKey = prefix !== "" ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value, compositeKey, result, depth + 1);
    } else {
      result[compositeKey] = value as Primitive | unknown[];
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix = "",
  result: FlattenedObject = {},
  seen = new WeakSet<object>()
): FlattenedObject {
  if (!isPlainObject(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (seen.has(input)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix}"`
    );
  }

  seen.add(input);

  const entries = Object.entries(input);

  if (entries.length === 0) {
    if (prefix !== "") {
      result[prefix] = {};
    }
    seen.delete(input);
    return result;
  }

  for (const [key, value] of entries) {
    if (typeof key !== "string") continue;

    const sanitizedKey = key.replace(/\./g, "\\.");
    const fullKey = prefix === "" ? sanitizedKey : `${prefix}.${sanitizedKey}`;

    if (isPlainObject(value)) {
      flattenObject(value, fullKey, result, seen);
    } else {
      result[fullKey] = value as Primitive;
    }
  }

  seen.delete(input);
  return result;
}

export default flattenObject;

type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function isTraversable(value: unknown): value is object {
  return isPlainObject(value) || Array.isArray(value);
}

function flattenInto(
  input: unknown,
  prefix: string,
  result: FlatObject,
  ancestors: WeakSet<object>
): void {
  if (!isTraversable(input)) {
    if (prefix) result[prefix] = input;
    return;
  }

  // Circular reference guard — store current node before recursing
  if (ancestors.has(input)) {
    if (prefix) result[prefix] = "[Circular]";
    return;
  }

  const entries: [string, unknown][] = Array.isArray(input)
    ? (input as unknown[]).map((v, i) => [String(i), v])
    : Object.entries(input as Record<string, unknown>);

  // Empty plain-object or array: preserve as a leaf so the key isn't silently dropped
  if (entries.length === 0) {
    if (prefix) result[prefix] = input;
    return;
  }

  ancestors.add(input);

  for (const [key, value] of entries) {
    // Guard against prototype-pollution keys
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const newKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isTraversable(value) && !ancestors.has(value)) {
      flattenInto(value, newKey, result, ancestors);
    } else {
      // Leaf: primitives, Dates, RegExps, other non-plain objects, or already-seen refs
      if (value !== null && typeof value === "object" && ancestors.has(value)) {
        result[newKey] = "[Circular]";
      } else {
        result[newKey] = value;
      }
    }
  }

  // Remove from ancestor set on the way back up so the same object can appear
  // in a sibling branch without being incorrectly flagged as circular
  ancestors.delete(input);
}

function flattenObject(input: unknown): FlatObject {
  if (input === null || input === undefined) return {};
  if (!isTraversable(input)) return {};

  const result: FlatObject = {};
  flattenInto(input, "", result, new WeakSet<object>());
  return result;
}

export default flattenObject;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const satisfies Record<keyof CronFields, FieldConfig>;

const FIELD_ORDER = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function assertInRange(value: number, config: FieldConfig, fieldName: string, context: string): void {
  if (!Number.isInteger(value) || !Number.isFinite(value)) {
    throw new RangeError(`Non-integer value ${value} in field '${fieldName}' (token: '${context}')`);
  }
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} in field '${fieldName}' is out of range [${config.min}, ${config.max}] (token: '${context}')`
    );
  }
}

function expandRange(start: number, end: number, step: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseToken(token: string, config: FieldConfig, fieldName: string): number[] {
  if (!token) {
    throw new SyntaxError(`Empty token in field '${fieldName}'`);
  }

  // Detect step suffix: <base>/<step>
  const slashIdx = token.indexOf("/");
  if (slashIdx !== -1) {
    const basePart = token.slice(0, slashIdx);
    const stepPart = token.slice(slashIdx + 1);

    if (!stepPart || !/^\d+$/.test(stepPart)) {
      throw new SyntaxError(`Invalid step value in '${token}' for field '${fieldName}'`);
    }
    const step = parseInt(stepPart, 10);
    if (step < 1) {
      throw new RangeError(`Step must be >= 1, got ${step} in '${token}' for field '${fieldName}'`);
    }

    if (basePart === "*") {
      return expandRange(config.min, config.max, step);
    }

    const dashIdx = basePart.indexOf("-");
    if (dashIdx !== -1) {
      const [startStr, endStr] = [basePart.slice(0, dashIdx), basePart.slice(dashIdx + 1)];
      if (!/^\d+$/.test(startStr) || !/^\d+$/.test(endStr)) {
        throw new SyntaxError(`Invalid range in '${token}' for field '${fieldName}'`);
      }
      const start = parseInt(startStr, 10);
      const end   = parseInt(endStr,   10);
      assertInRange(start, config, fieldName, token);
      assertInRange(end,   config, fieldName, token);
      if (start > end) {
        throw new RangeError(`Range start (${start}) > end (${end}) in '${token}' for field '${fieldName}'`);
      }
      return expandRange(start, end, step);
    }

    if (/^\d+$/.test(basePart)) {
      const start = parseInt(basePart, 10);
      assertInRange(start, config, fieldName, token);
      return expandRange(start, config.max, step);
    }

    throw new SyntaxError(`Unrecognised base '${basePart}' in '${token}' for field '${fieldName}'`);
  }

  // Wildcard with no step
  if (token === "*") {
    return expandRange(config.min, config.max, 1);
  }

  // Range without step: <start>-<end>
  const dashIdx = token.indexOf("-");
  if (dashIdx !== -1) {
    // Guard against leading negative numbers (ranges can't be negative in cron)
    if (dashIdx === 0) {
      throw new SyntaxError(`Unexpected '-' at start of '${token}' for field '${fieldName}'`);
    }
    const startStr = token.slice(0, dashIdx);
    const endStr   = token.slice(dashIdx + 1);
    if (!/^\d+$/.test(startStr) || !/^\d+$/.test(endStr)) {
      throw new SyntaxError(`Invalid range '${token}' for field '${fieldName}'`);
    }
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    assertInRange(start, config, fieldName, token);
    assertInRange(end,   config, fieldName, token);
    if (start > end) {
      throw new RangeError(`Range start (${start}) > end (${end}) in '${token}' for field '${fieldName}'`);
    }
    return expandRange(start, end, 1);
  }

  // Plain integer
  if (/^\d+$/.test(token)) {
    const value = parseInt(token, 10);
    assertInRange(value, config, fieldName, token);
    return [value];
  }

  throw new SyntaxError(`Unrecognised token '${token}' in field '${fieldName}'`);
}

function parseField(rawField: string, config: FieldConfig, fieldName: string): number[] {
  const parts = rawField.split(",");
  if (parts.length === 0 || (parts.length === 1 && parts[0] === "")) {
    throw new SyntaxError(`Empty field '${fieldName}'`);
  }

  const seen = new Set<number>();
  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) {
      throw new SyntaxError(`Empty segment in comma list for field '${fieldName}': '${rawField}'`);
    }
    for (const v of parseToken(trimmed, config, fieldName)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new SyntaxError("Cron expression must not be empty or whitespace-only");
  }

  const rawFields = trimmed.split(/\s+/);
  if (rawFields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${rawFields.length}: '${expression}'`
    );
  }

  const result = {} as CronFields;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name   = FIELD_ORDER[i];
    const config = FIELD_CONFIGS[name];
    result[name] = parseField(rawFields[i], config, name);
  }

  return result;
}

type PlainObject = { [key: string]: unknown };
type FlatObject = { [key: string]: unknown };

function isPlainObject(value: unknown): value is PlainObject {
  if (typeof value !== "object" || value === null || Array.isArray(value)) {
    return false;
  }
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flatten(
  obj: PlainObject,
  prefix: string,
  result: FlatObject,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(obj)) {
    // Circular reference — treat the node as a leaf to avoid infinite recursion
    result[prefix] = "[Circular]";
    return;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Preserve empty objects as leaf values so the key is not silently dropped
    if (prefix !== "") result[prefix] = obj;
    return;
  }

  ancestors.add(obj);

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value)) {
      flatten(value as PlainObject, newKey, result, ancestors);
    } else {
      result[newKey] = value;
    }
  }

  ancestors.delete(obj);
}

export default function flattenObject(obj: unknown): FlatObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : Array.isArray(obj) ? "array" : typeof obj
      }`
    );
  }

  const result: FlatObject = {};
  flatten(obj, "", result, new WeakSet());
  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: { maxDepth?: number; delimiter?: string } = {}
): FlattenedObject {
  const delimiter = options.delimiter ?? ".";
  const maxDepth = options.maxDepth ?? 100;

  if (delimiter.length === 0) {
    throw new Error("Delimiter must be a non-empty string.");
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `Expected a plain object, received: ${
        input === null ? "null" : Array.isArray(input) ? "array" : typeof input
      }`
    );
  }

  const result: FlattenedObject = {};
  const seen = new WeakSet<object>();

  function recurse(current: Record<string, unknown>, prefix: string, depth: number): void {
    if (depth > maxDepth) {
      throw new RangeError(
        `Maximum flattening depth of ${maxDepth} exceeded at key "${prefix}". Possible circular reference or excessively deep object.`
      );
    }

    if (seen.has(current)) {
      throw new RangeError(
        `Circular reference detected at key "${prefix}".`
      );
    }

    seen.add(current);

    const keys = Object.keys(current);

    if (keys.length === 0) {
      // Empty object: preserve the key with an empty-object sentinel if prefixed, skip if root
      if (prefix !== "") {
        // Represent empty objects as undefined — caller can decide, but we preserve the key
        result[prefix] = undefined;
      }
      seen.delete(current);
      return;
    }

    for (const key of keys) {
      if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

      const fullKey = prefix === "" ? key : `${prefix}${delimiter}${key}`;
      const value = current[key];

      if (isPlainObject(value)) {
        recurse(value as Record<string, unknown>, fullKey, depth + 1);
      } else if (Array.isArray(value)) {
        // Flatten arrays with index-based keys
        for (let i = 0; i < value.length; i++) {
          const arrayKey = `${fullKey}${delimiter}${i}`;
          const item = value[i];
          if (isPlainObject(item)) {
            recurse(item as Record<string, unknown>, arrayKey, depth + 1);
          } else {
            result[arrayKey] = item as Primitive;
          }
        }
      } else {
        result[fullKey] = value as Primitive;
      }
    }

    seen.delete(current);
  }

  recurse(input, "", 0);

  return result;
}

export default flattenObject;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
  name: string;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 7 },
] as const;

function clampAndDedupe(values: number[], min: number, max: number): number[] {
  const seen = new Set<number>();
  for (const v of values) {
    if (v >= min && v <= max) {
      seen.add(v);
    }
  }
  return Array.from(seen).sort((a, b) => a - b);
}

function isInteger(value: number): boolean {
  return Number.isInteger(value) && !Number.isNaN(value);
}

function parseNumber(raw: string, min: number, max: number, fieldName: string): number {
  const n = Number(raw.trim());
  if (!isInteger(n)) {
    throw new Error(`Invalid numeric value "${raw}" in field "${fieldName}"`);
  }
  if (n < min || n > max) {
    throw new Error(
      `Value ${n} out of range [${min}-${max}] in field "${fieldName}"`
    );
  }
  return n;
}

function parseWildcard(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => i + min);
}

function parseStep(raw: string, min: number, max: number, fieldName: string): number[] {
  const parts = raw.split("/");
  if (parts.length !== 2) {
    throw new Error(`Invalid step expression "${raw}" in field "${fieldName}"`);
  }

  const [rangePart, stepPart] = parts;
  const step = Number(stepPart.trim());

  if (!isInteger(step) || step < 1) {
    throw new Error(
      `Invalid step value "${stepPart}" in field "${fieldName}": must be a positive integer`
    );
  }

  let start: number;
  let end: number;

  if (rangePart.trim() === "*") {
    start = min;
    end = max;
  } else if (rangePart.includes("-")) {
    const [rangeStart, rangeEnd] = parseRange(rangePart, min, max, fieldName);
    start = rangeStart;
    end = rangeEnd;
  } else {
    start = parseNumber(rangePart, min, max, fieldName);
    end = max;
  }

  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(v);
  }
  return values;
}

function parseRange(raw: string, min: number, max: number, fieldName: string): [number, number] {
  const parts = raw.split("-");
  if (parts.length !== 2) {
    throw new Error(`Invalid range expression "${raw}" in field "${fieldName}"`);
  }

  const start = parseNumber(parts[0], min, max, fieldName);
  const end = parseNumber(parts[1], min, max, fieldName);

  if (start > end) {
    throw new Error(
      `Invalid range "${raw}" in field "${fieldName}": start (${start}) must not exceed end (${end})`
    );
  }

  return [start, end];
}

function parseRangeExpand(raw: string, min: number, max: number, fieldName: string): number[] {
  const [start, end] = parseRange(raw, min, max, fieldName);
  return Array.from({ length: end - start + 1 }, (_, i) => i + start);
}

function parseToken(token: string, min: number, max: number, fieldName: string): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new Error(`Empty token encountered in field "${fieldName}"`);
  }

  if (trimmed === "*") {
    return parseWildcard(min, max);
  }

  if (trimmed.includes("/")) {
    return parseStep(trimmed, min, max, fieldName);
  }

  if (trimmed.includes("-")) {
    return parseRangeExpand(trimmed, min, max, fieldName);
  }

  const n = parseNumber(trimmed, min, max, fieldName);
  return [n];
}

function parseField(raw: string, config: FieldConfig): number[] {
  const { min, max, name } = config;

  if (typeof raw !== "string") {
    throw new Error(`Field "${name}" must be a string`);
  }

  const trimmed = raw.trim();

  if (trimmed === "") {
    throw new Error(`Field "${name}" is empty`);
  }

  const tokens = trimmed.split(",");
  const allValues: number[] = [];

  for (const token of tokens) {
    const values = parseToken(token, min, max, name);
    allValues.push(...values);
  }

  const result = clampAndDedupe(allValues, min, max);

  // Normalize dayOfWeek: treat 7 as 0 (Sunday)
  if (name === "dayOfWeek") {
    const normalized = new Set<number>();
    for (const v of result) {
      normalized.add(v === 7 ? 0 : v);
    }
    return Array.from(normalized).sort((a, b) => a - b);
  }

  return result;
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, dayOfMonthRaw, monthRaw, dayOfWeekRaw] = fields;

  return {
    minute: parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour: parseField(hourRaw, FIELD_CONFIGS[1]),
    dayOfMonth: parseField(dayOfMonthRaw, FIELD_CONFIGS[2]),
    month: parseField(monthRaw, FIELD_CONFIGS[3]),
    dayOfWeek: parseField(dayOfWeekRaw, FIELD_CONFIGS[4]),
  };
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<FieldName, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

class CronParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CronParseError";
  }
}

function isInteger(value: number): boolean {
  return Number.isFinite(value) && Math.floor(value) === value;
}

function parseIntStrict(raw: string): number {
  const trimmed = raw.trim();
  if (trimmed === "" || !/^\d+$/.test(trimmed)) {
    throw new CronParseError(`Invalid integer: "${raw}"`);
  }
  return parseInt(trimmed, 10);
}

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (!isInteger(value) || value < config.min || value > config.max) {
    throw new CronParseError(
      `Value ${value} out of range [${config.min}, ${config.max}] in ${context}`
    );
  }
}

function expandRange(raw: string, config: FieldConfig, fieldName: FieldName): number[] {
  const parts = raw.split("-");
  if (parts.length !== 2) {
    throw new CronParseError(
      `Invalid range "${raw}" in field "${fieldName}"`
    );
  }

  const start = parseIntStrict(parts[0]);
  const end   = parseIntStrict(parts[1]);

  assertInRange(start, config, `range start in field "${fieldName}"`);
  assertInRange(end,   config, `range end in field "${fieldName}"`);

  if (start > end) {
    throw new CronParseError(
      `Range start ${start} > end ${end} in field "${fieldName}"`
    );
  }

  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function expandStep(raw: string, config: FieldConfig, fieldName: FieldName): number[] {
  const slashIdx = raw.indexOf("/");
  const basePart = raw.slice(0, slashIdx).trim();
  const stepPart = raw.slice(slashIdx + 1).trim();

  const step = parseIntStrict(stepPart);
  if (step <= 0) {
    throw new CronParseError(
      `Step value must be >= 1, got ${step} in field "${fieldName}"`
    );
  }

  let rangeStart: number;
  let rangeEnd: number;

  if (basePart === "*") {
    rangeStart = config.min;
    rangeEnd   = config.max;
  } else if (basePart.includes("-")) {
    // e.g. "1-5/2"
    const parts = basePart.split("-");
    if (parts.length !== 2) {
      throw new CronParseError(
        `Invalid step base range "${basePart}" in field "${fieldName}"`
      );
    }
    rangeStart = parseIntStrict(parts[0]);
    rangeEnd   = parseIntStrict(parts[1]);
    assertInRange(rangeStart, config, `step range start in field "${fieldName}"`);
    assertInRange(rangeEnd,   config, `step range end in field "${fieldName}"`);
    if (rangeStart > rangeEnd) {
      throw new CronParseError(
        `Step range start ${rangeStart} > end ${rangeEnd} in field "${fieldName}"`
      );
    }
  } else {
    // e.g. "5/15" — start at 5, step up to max
    rangeStart = parseIntStrict(basePart);
    assertInRange(rangeStart, config, `step base in field "${fieldName}"`);
    rangeEnd = config.max;
  }

  const result: number[] = [];
  for (let i = rangeStart; i <= rangeEnd; i += step) {
    result.push(i);
  }
  return result;
}

function parseToken(token: string, config: FieldConfig, fieldName: FieldName): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new CronParseError(`Empty token in field "${fieldName}"`);
  }

  // Wildcard
  if (trimmed === "*") {
    const result: number[] = [];
    for (let i = config.min; i <= config.max; i++) {
      result.push(i);
    }
    return result;
  }

  // Step value (contains slash)
  if (trimmed.includes("/")) {
    return expandStep(trimmed, config, fieldName);
  }

  // Range (contains dash but not a negative number — all cron values are non-negative)
  if (trimmed.includes("-")) {
    return expandRange(trimmed, config, fieldName);
  }

  // Plain integer
  const value = parseIntStrict(trimmed);
  assertInRange(value, config, `field "${fieldName}"`);
  return [value];
}

function parseField(raw: string, config: FieldConfig, fieldName: FieldName): number[] {
  if (typeof raw !== "string") {
    throw new CronParseError(`Field "${fieldName}" must be a string`);
  }

  // Comma-separated list — split and process each token
  const tokens = raw.split(",");
  if (tokens.length === 0) {
    throw new CronParseError(`Field "${fieldName}" is empty`);
  }

  const valueSet = new Set<number>();

  for (const token of tokens) {
    const values = parseToken(token, config, fieldName);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new CronParseError("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new CronParseError("Cron expression must not be empty");
  }

  // Normalize internal whitespace — split on one or more whitespace chars
  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new CronParseError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const config    = FIELD_CONFIGS[fieldName];
    result[fieldName] = parseField(parts[i], config, fieldName);
  }

  return result;
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<unknown>;
};

type FlattenedObject = Record<string, Primitive | Array<unknown>>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function sanitizeKey(key: string): string {
  // Escape dots in keys to avoid ambiguity
  return key.replace(/\./g, "\\.");
}

function flattenObject(
  input: unknown,
  options: {
    delimiter?: string;
    maxDepth?: number;
    escapeKeys?: boolean;
    arrayLeaf?: boolean;
  } = {}
): FlattenedObject {
  const {
    delimiter = ".",
    maxDepth = Infinity,
    escapeKeys = true,
    arrayLeaf = true,
  } = options;

  if (maxDepth !== Infinity && (!Number.isInteger(maxDepth) || maxDepth < 0)) {
    throw new RangeError(`maxDepth must be a non-negative integer, got: ${maxDepth}`);
  }

  if (!delimiter || typeof delimiter !== "string") {
    throw new TypeError(`delimiter must be a non-empty string, got: ${JSON.stringify(delimiter)}`);
  }

  const result: FlattenedObject = {};

  if (!isPlainObject(input)) {
    // Non-object input: return empty object (safe fallback)
    return result;
  }

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (isPlainObject(current) && depth < maxDepth) {
      const entries = Object.entries(current as NestedObject);

      if (entries.length === 0) {
        // Preserve empty objects as-is if they are nested
        if (prefix !== "") {
          result[prefix] = {} as unknown as Primitive;
        }
        return;
      }

      for (const [key, value] of entries) {
        const safeKey = escapeKeys ? sanitizeKey(key) : key;
        const newKey = prefix === "" ? safeKey : `${prefix}${delimiter}${safeKey}`;
        recurse(value, newKey, depth + 1);
      }
    } else if (Array.isArray(current) && arrayLeaf) {
      // Treat arrays as leaf values by default
      if (prefix !== "") {
        result[prefix] = current as Array<unknown>;
      }
    } else {
      if (prefix !== "") {
        result[prefix] = current as Primitive;
      }
    }
  }

  recurse(input, "", 0);

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type FlatValue = Primitive | Date | RegExp | Function | unknown[];

interface NestedObject {
  [key: string]: unknown;
}

type FlattenedObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map) return false;
  if (value instanceof Set) return false;
  if (value instanceof WeakMap) return false;
  if (value instanceof WeakSet) return false;
  if (Array.isArray(value)) return false;
  return true;
}

function flattenObjectInternal(
  obj: NestedObject,
  prefix: string,
  result: FlattenedObject,
  visited: WeakSet<object>
): void {
  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Preserve empty objects as leaf values when they're nested
    if (prefix !== "") {
      result[prefix] = obj;
    }
    return;
  }

  for (const key of keys) {
    // Guard against prototype pollution and non-own properties
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value = obj[key];
    const newKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value)) {
      if (visited.has(value)) {
        // Circular reference detected — treat as leaf to avoid infinite recursion
        result[newKey] = "[Circular]";
        continue;
      }
      visited.add(value);
      flattenObjectInternal(value, newKey, result, visited);
      visited.delete(value);
    } else {
      result[newKey] = value;
    }
  }
}

export default function flattenObject(input: unknown): FlattenedObject {
  if (input === null || input === undefined) return {};
  if (!isPlainObject(input)) return {};

  const result: FlattenedObject = {};
  const visited = new WeakSet<object>();
  visited.add(input);
  flattenObjectInternal(input, "", result, visited);
  return result;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: keyof CronExpression;
  min: number;
  max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 7 },
] as const;

const FIELD_COUNT = 5;

function isInteger(value: number): boolean {
  return Number.isInteger(value) && !Number.isNaN(value);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Invalid value ${value} in "${context}": must be an integer between ${min} and ${max}`
    );
  }
}

function parseNumber(token: string, min: number, max: number, context: string): number {
  const trimmed = token.trim();
  if (trimmed === "" || !/^-?\d+$/.test(trimmed)) {
    throw new SyntaxError(`Expected an integer in "${context}", got "${trimmed}"`);
  }
  const value = parseInt(trimmed, 10);
  assertInRange(value, min, max, context);
  return value;
}

function expandRange(start: number, end: number): number[] {
  if (start > end) {
    throw new RangeError(`Invalid range: start (${start}) must be <= end (${end})`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function deduplicateAndSort(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Empty segment in field "${fieldName}"`);
  }

  // Step value: */N or range/N
  if (trimmed.includes("/")) {
    const slashIndex = trimmed.indexOf("/");
    const baseStr = trimmed.slice(0, slashIndex);
    const stepStr = trimmed.slice(slashIndex + 1);

    if (stepStr === "" || !/^\d+$/.test(stepStr)) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in field "${fieldName}"`);
    }
    const step = parseInt(stepStr, 10);
    if (step <= 0) {
      throw new RangeError(`Step must be a positive integer in field "${fieldName}", got ${step}`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (baseStr === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (baseStr.includes("-")) {
      const dashIndex = baseStr.indexOf("-");
      rangeStart = parseNumber(baseStr.slice(0, dashIndex), min, max, fieldName);
      rangeEnd = parseNumber(baseStr.slice(dashIndex + 1), min, max, fieldName);
      if (rangeStart > rangeEnd) {
        throw new RangeError(
          `Range start (${rangeStart}) must be <= end (${rangeEnd}) in field "${fieldName}"`
        );
      }
    } else {
      rangeStart = parseNumber(baseStr, min, max, fieldName);
      rangeEnd = max;
    }

    const values: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: N-M
  if (trimmed.includes("-")) {
    const dashIndex = trimmed.indexOf("-");
    const start = parseNumber(trimmed.slice(0, dashIndex), min, max, fieldName);
    const end = parseNumber(trimmed.slice(dashIndex + 1), min, max, fieldName);
    if (start > end) {
      throw new RangeError(
        `Range start (${start}) must be <= end (${end}) in field "${fieldName}"`
      );
    }
    return expandRange(start, end);
  }

  // Wildcard
  if (trimmed === "*") {
    return expandRange(min, max);
  }

  // Single number
  const value = parseNumber(trimmed, min, max, fieldName);
  return [value];
}

function parseField(field: string, min: number, max: number, fieldName: string): number[] {
  if (field === null || field === undefined) {
    throw new TypeError(`Field "${fieldName}" is null or undefined`);
  }

  const trimmed = field.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Field "${fieldName}" is empty`);
  }

  // Comma-separated list
  const segments = trimmed.split(",");
  const allValues: number[] = [];

  for (const segment of segments) {
    const values = parseSegment(segment, min, max, fieldName);
    allValues.push(...values);
  }

  const result = deduplicateAndSort(allValues);

  if (result.length === 0) {
    throw new RangeError(`Field "${fieldName}" resolved to no valid values`);
  }

  return result;
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  // Normalize internal whitespace: split on any whitespace runs
  const fields = trimmed.split(/\s+/);

  if (fields.length !== FIELD_COUNT) {
    throw new SyntaxError(
      `Cron expression must have exactly ${FIELD_COUNT} fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_COUNT; i++) {
    const config = FIELD_CONFIGS[i];
    result[config.name] = parseField(fields[i], config.min, config.max, config.name);
  }

  // Normalize dayOfWeek: treat 7 (non-standard Sunday alias) as 0
  if (result.dayOfWeek.includes(7)) {
    const normalized = result.dayOfWeek
      .map((v) => (v === 7 ? 0 : v))
      .filter((v, idx, arr) => arr.indexOf(v) === idx)
      .sort((a, b) => a - b);
    result.dayOfWeek = normalized;
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: Primitive | unknown[] | object };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix = "",
  seen = new WeakSet<object>()
): FlatObject {
  if (input === null || input === undefined) {
    return prefix ? { [prefix]: input } : {};
  }

  if (!isPlainObject(input) && !Array.isArray(input)) {
    return prefix ? { [prefix]: input } : {};
  }

  const obj = input as Record<string | number, unknown>;

  if (seen.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix || "(root)"}"`
    );
  }

  const keys = Object.keys(obj);

  // Treat empty objects/arrays as leaf values (preserve them rather than losing the key)
  if (keys.length === 0) {
    return prefix ? { [prefix]: input } : {};
  }

  seen.add(obj);

  const result: FlatObject = {};

  for (const key of keys) {
    const value = obj[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value) || Array.isArray(value)) {
      const nested = flattenObject(value, flatKey, seen);
      Object.assign(result, nested);
    } else {
      result[flatKey] = value as Primitive;
    }
  }

  seen.delete(obj);

  return result;
}

export default flattenObject;

export type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

export type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldMeta = {
  readonly min: number;
  readonly max: number;
  readonly label: string;
};

const FIELD_META: Readonly<Record<CronField, FieldMeta>> = {
  minute:     { min: 0,  max: 59, label: "minute"     },
  hour:       { min: 0,  max: 23, label: "hour"       },
  dayOfMonth: { min: 1,  max: 31, label: "dayOfMonth" },
  month:      { min: 1,  max: 12, label: "month"      },
  dayOfWeek:  { min: 0,  max: 6,  label: "dayOfWeek"  },
} as const;

const FIELD_ORDER: readonly CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

function assertNonEmpty(value: string, context: string): void {
  if (value.trim() === "") {
    throw new Error(`Empty value encountered in field "${context}"`);
  }
}

function parseNonNegativeInteger(raw: string, fieldLabel: string): number {
  const trimmed = raw.trim();

  if (trimmed === "") {
    throw new Error(`Expected integer in field "${fieldLabel}", got empty string`);
  }

  if (!/^\d+$/.test(trimmed)) {
    throw new Error(
      `Invalid value "${trimmed}" in field "${fieldLabel}": expected a non-negative integer`
    );
  }

  const value = Number(trimmed);

  if (!Number.isInteger(value) || !Number.isFinite(value)) {
    throw new Error(
      `Could not parse "${trimmed}" as an integer in field "${fieldLabel}"`
    );
  }

  return value;
}

function assertInRange(value: number, min: number, max: number, fieldLabel: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} in field "${fieldLabel}" is out of the valid range [${min}, ${max}]`
    );
  }
}

function expandRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function applyStep(from: number, to: number, step: number, fieldLabel: string): number[] {
  if (step <= 0) {
    throw new Error(
      `Step value ${step} in field "${fieldLabel}" must be a positive integer`
    );
  }

  const result: number[] = [];

  for (let v = from; v <= to; v += step) {
    result.push(v);
  }

  if (result.length === 0) {
    throw new Error(
      `Step expression produces no values for range [${from}, ${to}] with step ${step} in field "${fieldLabel}"`
    );
  }

  return result;
}

function parseRangeToken(token: string, min: number, max: number, fieldLabel: string): number[] {
  const parts = token.split("-");

  if (parts.length !== 2) {
    throw new Error(
      `Invalid range expression "${token}" in field "${fieldLabel}": expected "start-end" format`
    );
  }

  const [startRaw, endRaw] = parts as [string, string];

  const start = parseNonNegativeInteger(startRaw, fieldLabel);
  const end   = parseNonNegativeInteger(endRaw,   fieldLabel);

  assertInRange(start, min, max, fieldLabel);
  assertInRange(end,   min, max, fieldLabel);

  if (start > end) {
    throw new Error(
      `Range start ${start} exceeds end ${end} in field "${fieldLabel}"`
    );
  }

  return expandRange(start, end);
}

function parseStepExpression(token: string, min: number, max: number, fieldLabel: string): number[] {
  const slashIdx = token.indexOf("/");

  if (slashIdx === -1) {
    throw new Error(`Internal error: expected "/" in step token "${token}"`);
  }

  const base    = token.slice(0, slashIdx);
  const stepRaw = token.slice(slashIdx + 1);

  if (base === "" || stepRaw === "") {
    throw new Error(
      `Malformed step expression "${token}" in field "${fieldLabel}"`
    );
  }

  const step = parseNonNegativeInteger(stepRaw, fieldLabel);

  if (base === "*") {
    return applyStep(min, max, step, fieldLabel);
  }

  if (base.includes("-")) {
    const rangeParts = base.split("-");

    if (rangeParts.length !== 2) {
      throw new Error(
        `Invalid range base "${base}" in step expression "${token}" for field "${fieldLabel}"`
      );
    }

    const [startRaw, endRaw] = rangeParts as [string, string];
    const rangeStart = parseNonNegativeInteger(startRaw, fieldLabel);
    const rangeEnd   = parseNonNegativeInteger(endRaw,   fieldLabel);

    assertInRange(rangeStart, min, max, fieldLabel);
    assertInRange(rangeEnd,   min, max, fieldLabel);

    if (rangeStart > rangeEnd) {
      throw new Error(
        `Range start ${rangeStart} exceeds end ${rangeEnd} in step expression "${token}" for field "${fieldLabel}"`
      );
    }

    return applyStep(rangeStart, rangeEnd, step, fieldLabel);
  }

  // Numeric base: treat as start/step up to max
  const start = parseNonNegativeInteger(base, fieldLabel);
  assertInRange(start, min, max, fieldLabel);

  return applyStep(start, max, step, fieldLabel);
}

function parseListToken(token: string, min: number, max: number, fieldLabel: string): number[] {
  const items = token.split(",");

  if (items.length === 0) {
    throw new Error(`Empty list in field "${fieldLabel}"`);
  }

  const seen   = new Set<number>();
  const values: number[] = [];

  for (const item of items) {
    const trimmedItem = item.trim();

    assertNonEmpty(trimmedItem, fieldLabel);

    let expanded: number[];

    if (trimmedItem.includes("-")) {
      expanded = parseRangeToken(trimmedItem, min, max, fieldLabel);
    } else {
      const num = parseNonNegativeInteger(trimmedItem, fieldLabel);
      assertInRange(num, min, max, fieldLabel);
      expanded = [num];
    }

    for (const v of expanded) {
      if (!seen.has(v)) {
        seen.add(v);
        values.push(v);
      }
    }
  }

  return values.sort((a, b) => a - b);
}

function parseFieldExpression(raw: string, meta: FieldMeta): number[] {
  const { min, max, label } = meta;
  const token = raw.trim();

  if (token === "") {
    throw new Error(`Field "${label}" is empty`);
  }

  // Wildcard
  if (token === "*") {
    return expandRange(min, max);
  }

  // Step expression (takes priority over other checks as it contains "/")
  if (token.includes("/")) {
    return parseStepExpression(token, min, max, label);
  }

  // Comma-separated list (may include ranges within items)
  if (token.includes(",")) {
    return parseListToken(token, min, max, label);
  }

  // Range
  if (token.includes("-")) {
    return parseRangeToken(token, min, max, label);
  }

  // Single value
  const value = parseNonNegativeInteger(token, label);
  assertInRange(value, min, max, label);

  return [value];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmedExpression = expression.trim();

  if (trimmedExpression === "") {
    throw new Error("Cron expression must not be empty");
  }

  const rawFields = trimmedExpression.split(/\s+/);

  if (rawFields.length !== 5) {
    throw new Error(
      `Cron expression must contain exactly 5 whitespace-separated fields, ` +
      `but received ${rawFields.length} field(s): "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldKey  = FIELD_ORDER[i] as CronField;
    const rawField  = rawFields[i] as string;
    const meta      = FIELD_META[fieldKey];

    result[fieldKey] = parseFieldExpression(rawField, meta);
  }

  return result;
}

type Primitive = string | number | boolean | bigint | symbol | null | undefined;
type FlattenableValue = Primitive | object;
type FlatOutput = Record<string, FlattenableValue>;

const isLeaf = (value: unknown): value is FlattenableValue => {
  if (value === null || value === undefined) return true;
  if (typeof value !== "object" && typeof value !== "function") return true;
  // Treat these built-in types as opaque leaf values
  if (
    value instanceof Date ||
    value instanceof RegExp ||
    value instanceof Error ||
    value instanceof Map ||
    value instanceof Set ||
    value instanceof WeakMap ||
    value instanceof WeakSet ||
    value instanceof ArrayBuffer ||
    ArrayBuffer.isView(value) ||
    typeof value === "function"
  ) {
    return true;
  }
  return false;
};

const recurse = (
  value: unknown,
  prefix: string,
  output: FlatOutput,
  visited: WeakSet<object>,
  depth: number,
  maxDepth: number
): void => {
  if (depth > maxDepth) {
    // Depth guard: treat over-deep nodes as leaves to prevent stack overflow
    output[prefix] = value as FlattenableValue;
    return;
  }

  if (isLeaf(value)) {
    if (prefix !== "") {
      output[prefix] = value as FlattenableValue;
    }
    return;
  }

  // value is a non-null object at this point
  const obj = value as object;

  if (visited.has(obj)) {
    // Circular reference — emit a sentinel rather than silently dropping the key
    output[prefix] = "[Circular]";
    return;
  }

  visited.add(obj);

  const entries = Object.entries(obj);

  if (entries.length === 0) {
    // Preserve empty objects/arrays as leaf values so keys are not silently lost
    if (prefix !== "") {
      output[prefix] = Array.isArray(obj) ? [] : {};
    }
    visited.delete(obj);
    return;
  }

  for (const [key, child] of entries) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    // Sanitise key segment: replace dots to avoid ambiguous round-trip
    const safeKey = key.replace(/\./g, "\\.");
    const nextPrefix = prefix === "" ? safeKey : `${prefix}.${safeKey}`;

    recurse(child, nextPrefix, output, visited, depth + 1, maxDepth);
  }

  visited.delete(obj);
};

const flattenObject = (
  input: unknown,
  maxDepth = 64
): FlatOutput => {
  if (input === null || input === undefined) {
    return {};
  }

  if (typeof input !== "object") {
    throw new TypeError(
      `flattenObject expects a plain object or array, received: ${typeof input}`
    );
  }

  if (
    typeof maxDepth !== "number" ||
    !Number.isFinite(maxDepth) ||
    maxDepth < 1
  ) {
    throw new RangeError(
      `maxDepth must be a finite number >= 1, received: ${maxDepth}`
    );
  }

  const output: FlatOutput = {};
  const visited = new WeakSet<object>();

  recurse(input, "", output, visited, 0, maxDepth);

  return output;
};

export default flattenObject;

type NestedObject = Record<string, unknown>;
type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenInto(
  obj: NestedObject,
  prefix: string,
  result: FlatObject,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(obj)) {
    throw new TypeError(
      `Circular reference detected${prefix ? ` at path "${prefix}"` : ""}`
    );
  }

  ancestors.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Preserve empty objects as leaf values so callers don't silently lose keys
    if (prefix !== "") {
      result[prefix] = {};
    }
    ancestors.delete(obj);
    return;
  }

  for (const key of keys) {
    // Guard against prototype-polluted keys sneaking through
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value: unknown = obj[key];
    const path = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      flattenInto(value, path, result, ancestors);
    } else {
      result[path] = value;
    }
  }

  ancestors.delete(obj);
}

export default function flattenObject(obj: NestedObject): FlatObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : Array.isArray(obj) ? "array" : typeof obj
      }`
    );
  }

  const result: FlatObject = {};
  flattenInto(obj, "", result, new WeakSet<object>());
  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  input: unknown,
  prefix: string = "",
  seen: WeakSet<object> = new WeakSet(),
  maxDepth: number = 100,
  currentDepth: number = 0
): FlatObject {
  if (input === null || input === undefined) {
    return prefix ? { [prefix]: input as Primitive } : {};
  }

  if (typeof input !== "object" || Array.isArray(input)) {
    return prefix ? { [prefix]: input as Primitive | unknown[] } : {};
  }

  if (currentDepth > maxDepth) {
    console.warn(
      `flattenObject: max depth of ${maxDepth} exceeded at key "${prefix}". Stopping recursion.`
    );
    return prefix ? { [prefix]: input as unknown } as FlatObject : {};
  }

  if (seen.has(input as object)) {
    console.warn(
      `flattenObject: circular reference detected at key "${prefix}". Skipping.`
    );
    return prefix ? { [prefix]: "[Circular]" } : {};
  }

  seen.add(input as object);

  const result: FlatObject = {};
  const obj = input as Record<string, unknown>;
  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) {
      result[prefix] = {} as unknown as Primitive;
    }
    seen.delete(input as object);
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) {
      continue;
    }

    const safeKey = String(key);
    if (safeKey.length === 0) {
      console.warn(
        `flattenObject: encountered empty string key at prefix "${prefix}". Skipping.`
      );
      continue;
    }

    const fullKey = prefix.length > 0 ? `${prefix}.${safeKey}` : safeKey;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      const nested = flattenObject(value, fullKey, seen, maxDepth, currentDepth + 1);
      Object.assign(result, nested);
    } else {
      result[fullKey] = value as Primitive | unknown[];
    }
  }

  seen.delete(input as object);
  return result;
}

export default flattenObject;

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldSpec {
  readonly name: keyof ParsedCron;
  readonly min: number;
  readonly max: number;
  /** Highest accepted value during parsing (may exceed max due to aliases, e.g. dow=7≡0) */
  readonly parseMax: number;
}

const FIELD_SPECS: readonly FieldSpec[] = [
  { name: "minute",     min: 0, max: 59, parseMax: 59 },
  { name: "hour",       min: 0, max: 23, parseMax: 23 },
  { name: "dayOfMonth", min: 1, max: 31, parseMax: 31 },
  { name: "month",      min: 1, max: 12, parseMax: 12 },
  { name: "dayOfWeek",  min: 0, max:  6, parseMax:  7 }, // 7 = Sunday alias for 0
] as const;

// ---------------------------------------------------------------------------
// Low-level helpers
// ---------------------------------------------------------------------------

function assertNonNegativeInteger(raw: string, fieldName: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(
      `Invalid value "${raw}" in field "${fieldName}" (${context}): must be a non-negative integer.`
    );
  }
  return parseInt(raw, 10);
}

function assertInRange(
  value: number,
  min: number,
  max: number,
  fieldName: string,
  context: string
): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} in field "${fieldName}" (${context}) is out of allowed range [${min}, ${max}].`
    );
  }
}

// ---------------------------------------------------------------------------
// Segment parsers  (comma-separated items are split before these are called)
// ---------------------------------------------------------------------------

/** Expand a single integer token, e.g. "5". */
function parseExactValue(token: string, spec: FieldSpec): number[] {
  const n = assertNonNegativeInteger(token, spec.name, "exact value");
  assertInRange(n, spec.min, spec.parseMax, spec.name, "exact value");
  return [n];
}

/** Expand a range token, e.g. "1-5". */
function parseRangeToken(token: string, spec: FieldSpec): number[] {
  const dashIdx = token.indexOf("-");
  const startRaw = token.slice(0, dashIdx).trim();
  const endRaw   = token.slice(dashIdx + 1).trim();

  if (!startRaw || !endRaw) {
    throw new Error(`Malformed range "${token}" in field "${spec.name}": both start and end are required.`);
  }

  const start = assertNonNegativeInteger(startRaw, spec.name, "range start");
  const end   = assertNonNegativeInteger(endRaw,   spec.name, "range end");

  assertInRange(start, spec.min, spec.parseMax, spec.name, "range start");
  assertInRange(end,   spec.min, spec.parseMax, spec.name, "range end");

  if (start > end) {
    throw new Error(
      `Range start ${start} > range end ${end} in field "${spec.name}". Reverse ranges are not supported.`
    );
  }

  const values: number[] = [];
  for (let i = start; i <= end; i++) values.push(i);
  return values;
}

/** Expand a step token, e.g. "*/15", "1-5/2", "0/10". */
function parseStepToken(token: string, spec: FieldSpec): number[] {
  const slashIdx = token.indexOf("/");
  const base     = token.slice(0, slashIdx).trim();
  const stepRaw  = token.slice(slashIdx + 1).trim();

  if (!base || !stepRaw) {
    throw new Error(`Malformed step expression "${token}" in field "${spec.name}": base and step are both required.`);
  }

  const step = assertNonNegativeInteger(stepRaw, spec.name, "step value");
  if (step === 0) {
    throw new Error(`Step value must be ≥ 1 in field "${spec.name}", got 0.`);
  }

  let rangeMin: number;
  let rangeMax: number;

  if (base === "*") {
    rangeMin = spec.min;
    rangeMax = spec.parseMax;
  } else if (base.includes("-")) {
    const dashIdx = base.indexOf("-");
    const startRaw = base.slice(0, dashIdx).trim();
    const endRaw   = base.slice(dashIdx + 1).trim();

    if (!startRaw || !endRaw) {
      throw new Error(`Malformed range in step expression "${token}" in field "${spec.name}".`);
    }

    rangeMin = assertNonNegativeInteger(startRaw, spec.name, "step range start");
    rangeMax = assertNonNegativeInteger(endRaw,   spec.name, "step range end");

    assertInRange(rangeMin, spec.min, spec.parseMax, spec.name, "step range start");
    assertInRange(rangeMax, spec.min, spec.parseMax, spec.name, "step range end");

    if (rangeMin > rangeMax) {
      throw new Error(
        `Step range start ${rangeMin} > end ${rangeMax} in field "${spec.name}".`
      );
    }
  } else {
    // bare number: treat as "n/step" meaning start at n and step to parseMax
    rangeMin = assertNonNegativeInteger(base, spec.name, "step start");
    rangeMax = spec.parseMax;
    assertInRange(rangeMin, spec.min, spec.parseMax, spec.name, "step start");
  }

  const values: number[] = [];
  for (let i = rangeMin; i <= rangeMax; i += step) values.push(i);
  return values;
}

/** Dispatch a single comma-separated segment to the right parser. */
function parseSegment(segment: string, spec: FieldSpec): number[] {
  const s = segment.trim();

  if (!s) {
    throw new Error(`Empty segment encountered in field "${spec.name}".`);
  }

  // Step expressions take priority (they can also contain ranges and wildcards)
  if (s.includes("/")) return parseStepToken(s, spec);

  // Pure wildcard
  if (s === "*") {
    const values: number[] = [];
    for (let i = spec.min; i <= spec.max; i++) values.push(i);
    return values;
  }

  // Range (must check before single value because ranges contain "-")
  if (s.includes("-")) return parseRangeToken(s, spec);

  // Single integer
  return parseExactValue(s, spec);
}

// ---------------------------------------------------------------------------
// Field-level parser
// ---------------------------------------------------------------------------

function parseField(raw: string, spec: FieldSpec): number[] {
  if (typeof raw !== "string" || raw.trim() === "") {
    throw new Error(`Field "${spec.name}" is empty or missing.`);
  }

  const segments = raw.trim().split(",");
  const seen = new Set<number>();

  for (const segment of segments) {
    for (const value of parseSegment(segment, spec)) {
      // Normalise dayOfWeek 7 → 0 (both mean Sunday)
      const normalised = spec.name === "dayOfWeek" && value === 7 ? 0 : value;
      seen.add(normalised);
    }
  }

  if (seen.size === 0) {
    throw new Error(`Field "${spec.name}" produced no values — check your expression.`);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron: expected a string, received ${typeof expression}.`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new Error("parseCron: cron expression must not be empty.");
  }

  // Split on any run of whitespace; guard against exotic Unicode spaces too
  const fields = trimmed.split(/[ \t\r\n\f\v]+/);

  if (fields.length !== 5) {
    throw new Error(
      `parseCron: expected exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `but found ${fields.length} in "${expression}".`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_SPECS[0]),
    hour:       parseField(hourRaw,   FIELD_SPECS[1]),
    dayOfMonth: parseField(domRaw,    FIELD_SPECS[2]),
    month:      parseField(monthRaw,  FIELD_SPECS[3]),
    dayOfWeek:  parseField(dowRaw,    FIELD_SPECS[4]),
  };
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<unknown>;
};

type FlattenedObject = Record<string, Primitive | Array<unknown>>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function sanitizeKey(key: string): string {
  // Escape dots in keys to avoid ambiguity
  return key.replace(/\./g, "\\.");
}

function flattenObject(
  input: unknown,
  options: {
    delimiter?: string;
    maxDepth?: number;
    escapeKeys?: boolean;
    preserveArrays?: boolean;
  } = {}
): FlattenedObject {
  const {
    delimiter = ".",
    maxDepth = Infinity,
    escapeKeys = true,
    preserveArrays = true,
  } = options;

  if (!isPlainObject(input)) {
    if (input === null || input === undefined) return {};
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        Array.isArray(input) ? "array" : typeof input
      }`
    );
  }

  if (maxDepth !== Infinity && (!Number.isInteger(maxDepth) || maxDepth < 0)) {
    throw new RangeError("maxDepth must be a non-negative integer or Infinity");
  }

  const result: FlattenedObject = {};
  const seen = new WeakSet<object>();

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (!isPlainObject(current)) {
      result[prefix] = current as Primitive | Array<unknown>;
      return;
    }

    if (seen.has(current as object)) {
      throw new TypeError(
        `Circular reference detected at key: "${prefix}"`
      );
    }

    const keys = Object.keys(current as NestedObject);

    // Treat empty objects as leaf values
    if (keys.length === 0) {
      if (prefix !== "") {
        result[prefix] = {};
      }
      return;
    }

    if (depth >= maxDepth) {
      result[prefix] = current as Primitive;
      return;
    }

    seen.add(current as object);

    for (const key of keys) {
      const safeKey = escapeKeys ? sanitizeKey(key) : key;
      const nextPrefix = prefix === "" ? safeKey : `${prefix}${delimiter}${safeKey}`;
      const value = (current as NestedObject)[key];

      if (preserveArrays && Array.isArray(value)) {
        result[nextPrefix] = value;
      } else if (isPlainObject(value)) {
        recurse(value, nextPrefix, depth + 1);
      } else {
        result[nextPrefix] = value as Primitive;
      }
    }

    seen.delete(current as object);
  }

  recurse(input, "", 0);
  return result;
}

export default flattenObject;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof CronExpression;

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_RANGES: Record<CronField, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
} as const;

const FIELD_ORDER: readonly CronField[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
] as const;

function isNonNegativeInteger(s: string): boolean {
  return /^\d+$/.test(s);
}

function parseStrictInt(s: string, context: string): number {
  if (!isNonNegativeInteger(s)) {
    throw new Error(`Expected a non-negative integer, got "${s}" in "${context}"`);
  }
  return parseInt(s, 10);
}

function assertInRange(value: number, range: FieldRange, context: string): void {
  if (value < range.min || value > range.max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${range.min}–${range.max}] in "${context}"`
    );
  }
}

function expandRange(start: number, end: number, step: number): number[] {
  if (step <= 0) {
    throw new Error(`Step must be a positive integer, got ${step}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parsePart(part: string, fieldRange: FieldRange): number[] {
  if (part === "") {
    throw new Error(`Empty segment part encountered`);
  }

  const slashIndex = part.indexOf("/");

  if (slashIndex !== -1) {
    if ((part.match(/\//g) ?? []).length > 1) {
      throw new Error(`Multiple "/" separators are not allowed in segment "${part}"`);
    }

    const baseStr = part.slice(0, slashIndex);
    const stepStr = part.slice(slashIndex + 1);

    if (stepStr === "") {
      throw new Error(`Missing step value after "/" in "${part}"`);
    }
    const step = parseStrictInt(stepStr, part);
    if (step === 0) {
      throw new Error(`Step value must be greater than zero in "${part}"`);
    }

    let start: number;
    let end: number;

    if (baseStr === "*") {
      start = fieldRange.min;
      end = fieldRange.max;
    } else {
      const dashIndex = baseStr.indexOf("-");
      if (dashIndex !== -1) {
        if ((baseStr.match(/-/g) ?? []).length > 1) {
          throw new Error(`Multiple "-" separators are not allowed in range "${baseStr}" in "${part}"`);
        }
        const startStr = baseStr.slice(0, dashIndex);
        const endStr   = baseStr.slice(dashIndex + 1);
        if (startStr === "" || endStr === "") {
          throw new Error(`Incomplete range "${baseStr}" in "${part}"`);
        }
        start = parseStrictInt(startStr, part);
        end   = parseStrictInt(endStr,   part);
        assertInRange(start, fieldRange, part);
        assertInRange(end,   fieldRange, part);
        if (start > end) {
          throw new Error(`Range start ${start} exceeds range end ${end} in "${part}"`);
        }
      } else {
        start = parseStrictInt(baseStr, part);
        assertInRange(start, fieldRange, part);
        end = fieldRange.max;
      }
    }

    return expandRange(start, end, step);
  }

  if (part === "*") {
    return expandRange(fieldRange.min, fieldRange.max, 1);
  }

  const dashIndex = part.indexOf("-");
  if (dashIndex !== -1) {
    if ((part.match(/-/g) ?? []).length > 1) {
      throw new Error(`Multiple "-" separators are not allowed in range "${part}"`);
    }
    const startStr = part.slice(0, dashIndex);
    const endStr   = part.slice(dashIndex + 1);
    if (startStr === "" || endStr === "") {
      throw new Error(`Incomplete range "${part}"`);
    }
    const start = parseStrictInt(startStr, part);
    const end   = parseStrictInt(endStr,   part);
    assertInRange(start, fieldRange, part);
    assertInRange(end,   fieldRange, part);
    if (start > end) {
      throw new Error(`Range start ${start} exceeds range end ${end} in "${part}"`);
    }
    return expandRange(start, end, 1);
  }

  const num = parseStrictInt(part, part);
  assertInRange(num, fieldRange, part);
  return [num];
}

function parseField(raw: string, fieldRange: FieldRange, fieldName: CronField): number[] {
  const trimmed = raw.trim();

  if (trimmed === "") {
    throw new Error(`Field "${fieldName}" must not be empty`);
  }

  if (trimmed.includes(",")) {
    const parts = trimmed.split(",");
    const seen = new Set<number>();

    for (const part of parts) {
      const trimmedPart = part.trim();
      if (trimmedPart === "") {
        throw new Error(
          `Empty element in comma-separated list for field "${fieldName}": "${trimmed}"`
        );
      }
      if (trimmedPart === "*") {
        throw new Error(
          `Wildcard "*" is not meaningful inside a comma-separated list for field "${fieldName}"`
        );
      }
      for (const v of parsePart(trimmedPart, fieldRange)) {
        seen.add(v);
      }
    }

    return Array.from(seen).sort((a, b) => a - b);
  }

  return parsePart(trimmed, fieldRange);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string argument, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const rawFields = trimmed.split(/\s+/);

  if (rawFields.length !== 5) {
    throw new Error(
      `Cron expression requires exactly 5 fields ` +
      `(minute hour dayOfMonth month dayOfWeek), but got ${rawFields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName  = FIELD_ORDER[i];
    const fieldRange = FIELD_RANGES[fieldName];
    const rawField   = rawFields[i];

    try {
      result[fieldName] = parseField(rawField, fieldRange, fieldName);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid cron field "${fieldName}" (position ${i + 1}): ${message}`);
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  maxDepth: number = 100
): FlattenedObject {
  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, got: ${Array.isArray(input) ? "array" : typeof input}`
    );
  }

  const result: FlattenedObject = {};

  function recurse(
    current: Record<string, unknown>,
    prefix: string,
    depth: number
  ): void {
    if (depth > maxDepth) {
      throw new RangeError(
        `flattenObject exceeded maximum depth of ${maxDepth}. Possible circular reference or deeply nested structure.`
      );
    }

    const keys = Object.keys(current);

    for (const key of keys) {
      if (key === "") continue;

      const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
      const value = current[key];

      if (isPlainObject(value)) {
        const childKeys = Object.keys(value);
        if (childKeys.length === 0) {
          // Empty objects produce no keys — silently skip
          continue;
        }
        recurse(value, fullKey, depth + 1);
      } else if (Array.isArray(value)) {
        // Flatten arrays with index-based keys
        for (let i = 0; i < value.length; i++) {
          const indexedKey = `${fullKey}.${i}`;
          const element = value[i];
          if (isPlainObject(element)) {
            const childKeys = Object.keys(element);
            if (childKeys.length > 0) {
              recurse(element, indexedKey, depth + 1);
            }
          } else if (!Array.isArray(element)) {
            result[indexedKey] = element as Primitive;
          } else {
            // Nested arrays: treat as opaque primitive (JSON-serialized)
            result[indexedKey] = JSON.stringify(element);
          }
        }
      } else {
        result[fullKey] = value as Primitive;
      }
    }
  }

  recurse(input, "", 0);

  return result;
}

export default flattenObject;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
  name: string;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { min: 0, max: 59, name: "minute" },
  { min: 0, max: 23, name: "hour" },
  { min: 1, max: 31, name: "dayOfMonth" },
  { min: 1, max: 12, name: "month" },
  { min: 0, max: 7, name: "dayOfWeek" },
] as const;

class CronParseError extends Error {
  constructor(message: string) {
    super(`CronParseError: ${message}`);
    this.name = "CronParseError";
  }
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new CronParseError(
      `Value ${value} is out of range [${min}, ${max}] in field "${context}"`
    );
  }
}

function parseNumber(token: string, config: FieldConfig): number {
  const trimmed = token.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new CronParseError(
      `Expected a number but got "${trimmed}" in field "${config.name}"`
    );
  }
  const value = parseInt(trimmed, 10);
  assertInRange(value, config.min, config.max, config.name);
  return value;
}

function expandRange(start: number, end: number, config: FieldConfig): number[] {
  if (start > end) {
    throw new CronParseError(
      `Range start ${start} is greater than end ${end} in field "${config.name}"`
    );
  }
  assertInRange(start, config.min, config.max, config.name);
  assertInRange(end, config.min, config.max, config.name);

  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function applyStep(values: number[], step: number, config: FieldConfig): number[] {
  if (!Number.isInteger(step) || step < 1) {
    throw new CronParseError(
      `Step value must be a positive integer, got ${step} in field "${config.name}"`
    );
  }
  return values.filter((_, index) => index % step === 0);
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new CronParseError(`Empty segment found in field "${config.name}"`);
  }

  // Handle step values: "*/step" or "start-end/step"
  if (trimmed.includes("/")) {
    const parts = trimmed.split("/");
    if (parts.length !== 2) {
      throw new CronParseError(
        `Invalid step expression "${trimmed}" in field "${config.name}"`
      );
    }

    const [rangePart, stepPart] = parts;

    if (!/^\d+$/.test(stepPart.trim())) {
      throw new CronParseError(
        `Step must be a positive integer, got "${stepPart}" in field "${config.name}"`
      );
    }

    const step = parseInt(stepPart.trim(), 10);
    let baseValues: number[];

    if (rangePart.trim() === "*") {
      baseValues = expandRange(config.min, config.max, config);
    } else if (rangePart.trim().includes("-")) {
      const rangeParts = rangePart.trim().split("-");
      if (rangeParts.length !== 2) {
        throw new CronParseError(
          `Invalid range "${rangePart}" in field "${config.name}"`
        );
      }
      const start = parseNumber(rangeParts[0], config);
      const end = parseNumber(rangeParts[1], config);
      baseValues = expandRange(start, end, config);
    } else {
      const start = parseNumber(rangePart, config);
      baseValues = expandRange(start, config.max, config);
    }

    return applyStep(baseValues, step, config);
  }

  // Handle wildcard
  if (trimmed === "*") {
    return expandRange(config.min, config.max, config);
  }

  // Handle range: "start-end"
  if (trimmed.includes("-")) {
    const parts = trimmed.split("-");
    if (parts.length !== 2) {
      throw new CronParseError(
        `Invalid range expression "${trimmed}" in field "${config.name}"`
      );
    }
    const start = parseNumber(parts[0], config);
    const end = parseNumber(parts[1], config);
    return expandRange(start, end, config);
  }

  // Handle plain number
  return [parseNumber(trimmed, config)];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (typeof field !== "string") {
    throw new CronParseError(`Field "${config.name}" must be a string`);
  }

  const trimmed = field.trim();

  if (trimmed === "") {
    throw new CronParseError(`Field "${config.name}" cannot be empty`);
  }

  // Handle comma-separated list
  const segments = trimmed.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment, config);
    for (const value of values) {
      valueSet.add(value);
    }
  }

  // Normalize dayOfWeek: treat 7 as 0 (both represent Sunday)
  if (config.name === "dayOfWeek" && valueSet.has(7)) {
    valueSet.delete(7);
    valueSet.add(0);
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new CronParseError("Cron expression must be a string");
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new CronParseError("Cron expression cannot be empty");
  }

  // Normalize whitespace: split on one or more whitespace characters
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new CronParseError(
      `Expected 5 fields but got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  return {
    minute: parseField(minuteField, FIELD_CONFIGS[0]),
    hour: parseField(hourField, FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domField, FIELD_CONFIGS[2]),
    month: parseField(monthField, FIELD_CONFIGS[3]),
    dayOfWeek: parseField(dowField, FIELD_CONFIGS[4]),
  };
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: Readonly<Record<FieldName, FieldConfig>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER: ReadonlyArray<FieldName> = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function buildRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (!Number.isInteger(value) || value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${config.min}–${config.max}] in segment "${context}"`
    );
  }
}

function parseSingleValue(raw: string, config: FieldConfig): number {
  const n = Number(raw);
  if (!Number.isInteger(n) || String(n) !== raw.trim()) {
    throw new TypeError(`Invalid numeric value "${raw}"`);
  }
  assertInRange(n, config, raw);
  return n;
}

function parseRange(segment: string, config: FieldConfig): number[] {
  const parts = segment.split("-");
  if (parts.length !== 2) {
    throw new SyntaxError(`Invalid range expression "${segment}": expected exactly one "-" separator`);
  }
  const start = parseSingleValue(parts[0], config);
  const end   = parseSingleValue(parts[1], config);
  if (start > end) {
    throw new RangeError(
      `Range start (${start}) must be ≤ range end (${end}) in "${segment}"`
    );
  }
  return buildRange(start, end);
}

function parseStep(segment: string, config: FieldConfig): number[] {
  const slashIndex = segment.indexOf("/");
  const basePart   = segment.slice(0, slashIndex);
  const stepPart   = segment.slice(slashIndex + 1);

  const step = Number(stepPart);
  if (!Number.isInteger(step) || step <= 0) {
    throw new RangeError(
      `Step value must be a positive integer, got "${stepPart}" in "${segment}"`
    );
  }

  let rangeStart: number;
  let rangeEnd: number;

  if (basePart === "*") {
    rangeStart = config.min;
    rangeEnd   = config.max;
  } else if (basePart.includes("-")) {
    const parts = basePart.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range base "${basePart}" in step expression "${segment}"`);
    }
    rangeStart = parseSingleValue(parts[0], config);
    rangeEnd   = parseSingleValue(parts[1], config);
    if (rangeStart > rangeEnd) {
      throw new RangeError(
        `Range start (${rangeStart}) must be ≤ range end (${rangeEnd}) in "${segment}"`
      );
    }
  } else {
    rangeStart = parseSingleValue(basePart, config);
    rangeEnd   = config.max;
  }

  const result: number[] = [];
  for (let i = rangeStart; i <= rangeEnd; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  if (segment === "") {
    throw new SyntaxError("Empty field segment is not allowed");
  }

  if (segment === "*") {
    return buildRange(config.min, config.max);
  }

  if (segment.includes("/")) {
    return parseStep(segment, config);
  }

  if (segment.includes("-")) {
    return parseRange(segment, config);
  }

  return [parseSingleValue(segment, config)];
}

function parseField(field: string, config: FieldConfig, fieldName: string): number[] {
  if (field === "") {
    throw new SyntaxError(`Field "${fieldName}" is empty`);
  }

  const segments = field.split(",");
  if (segments.length === 0) {
    throw new SyntaxError(`Field "${fieldName}" contains no segments`);
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Field "${fieldName}" contains an empty segment in "${field}"`);
    }
    for (const v of parseSegment(trimmed, config)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name   = FIELD_ORDER[i];
    const config = FIELD_CONFIGS[name];
    result[name] = parseField(fields[i], config, name);
  }

  return result;
}

export default parseCron;

