type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  maxDepth: number = 100
): FlattenedObject {
  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : Array.isArray(input) ? "array" : typeof input
      }`
    );
  }

  const result: FlattenedObject = {};

  function recurse(
    current: Record<string, unknown>,
    prefix: string,
    depth: number
  ): void {
    if (depth > maxDepth) {
      throw new RangeError(
        `flattenObject exceeded maximum depth of ${maxDepth}. Possible circular reference or deeply nested structure.`
      );
    }

    const keys = Object.keys(current);

    if (keys.length === 0 && prefix !== "") {
      // Empty object leaf — preserve as empty object marker? Convention: skip.
      // Some implementations store `{}` but dot-notation keys require a scalar value.
      // We skip silently to avoid storing non-primitive values.
      return;
    }

    for (const key of keys) {
      if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

      const fullKey = prefix === "" ? key : `${prefix}.${key}`;
      const value = current[key];

      if (isPlainObject(value)) {
        const nested = value as Record<string, unknown>;
        const nestedKeys = Object.keys(nested);

        if (nestedKeys.length === 0) {
          // Empty nested object: nothing to flatten, skip.
          continue;
        }

        recurse(nested, fullKey, depth + 1);
      } else if (Array.isArray(value)) {
        // Flatten array entries with index-based keys
        for (let i = 0; i < value.length; i++) {
          const indexedKey = `${fullKey}.${i}`;
          const item = value[i];

          if (isPlainObject(item)) {
            recurse(item as Record<string, unknown>, indexedKey, depth + 1);
          } else if (!Array.isArray(item)) {
            result[indexedKey] = item as Primitive;
          } else {
            // Nested arrays: recurse by wrapping in a synthetic object
            recurse({ [i]: item }, fullKey, depth + 1);
          }
        }
      } else {
        result[fullKey] = value as Primitive;
      }
    }
  }

  recurse(input, "", 0);

  return result;
}

export default flattenObject;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_NAMES: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function parseStrictInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Expected a non-negative integer for ${context}, got: "${raw}"`);
  }
  const n = parseInt(trimmed, 10);
  if (!Number.isFinite(n)) {
    throw new Error(`Parsed value overflows for ${context}: "${raw}"`);
  }
  return n;
}

function expandRange(
  start: number,
  end: number,
  step: number,
  min: number,
  max: number,
  context: string,
): number[] {
  if (step <= 0) {
    throw new Error(`Step must be a positive integer in ${context}, got: ${step}`);
  }
  if (start < min || start > max) {
    throw new Error(`Range start ${start} out of bounds [${min}, ${max}] in ${context}`);
  }
  if (end < min || end > max) {
    throw new Error(`Range end ${end} out of bounds [${min}, ${max}] in ${context}`);
  }
  if (start > end) {
    throw new Error(`Range start (${start}) must not exceed range end (${end}) in ${context}`);
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  const s = segment.trim();

  if (s === "") {
    throw new Error(`Empty segment found in field "${fieldName}"`);
  }

  const hasSlash = s.includes("/");
  const hasDash = s.includes("-");

  if (hasSlash) {
    const slashIdx = s.indexOf("/");
    const baseStr = s.slice(0, slashIdx);
    const stepStr = s.slice(slashIdx + 1);

    if (stepStr.trim() === "") {
      throw new Error(`Missing step value after "/" in field "${fieldName}": "${s}"`);
    }
    if (stepStr.includes("/")) {
      throw new Error(`Multiple "/" characters not allowed in field "${fieldName}": "${s}"`);
    }

    const step = parseStrictInteger(stepStr, `step in field "${fieldName}"`);
    if (step === 0) {
      throw new Error(`Step value must be >= 1 in field "${fieldName}": "${s}"`);
    }

    if (baseStr === "*") {
      return expandRange(min, max, step, min, max, `field "${fieldName}"`);
    }

    if (baseStr.includes("-")) {
      const dashIdx = baseStr.indexOf("-");
      const start = parseStrictInteger(baseStr.slice(0, dashIdx), `range start in field "${fieldName}"`);
      const end   = parseStrictInteger(baseStr.slice(dashIdx + 1), `range end in field "${fieldName}"`);
      return expandRange(start, end, step, min, max, `field "${fieldName}"`);
    }

    // Single number with step: "N/step" means N to max stepping by step
    const start = parseStrictInteger(baseStr, `start in field "${fieldName}"`);
    if (start < min || start > max) {
      throw new Error(`Value ${start} out of bounds [${min}, ${max}] in field "${fieldName}"`);
    }
    return expandRange(start, max, step, min, max, `field "${fieldName}"`);
  }

  if (s === "*") {
    return expandRange(min, max, 1, min, max, `field "${fieldName}"`);
  }

  if (hasDash) {
    const dashIdx = s.indexOf("-");
    const startStr = s.slice(0, dashIdx);
    const endStr   = s.slice(dashIdx + 1);

    if (startStr.trim() === "" || endStr.trim() === "") {
      throw new Error(`Malformed range in field "${fieldName}": "${s}"`);
    }
    if (endStr.includes("-")) {
      throw new Error(`Ambiguous multiple dashes in field "${fieldName}": "${s}"`);
    }

    const start = parseStrictInteger(startStr, `range start in field "${fieldName}"`);
    const end   = parseStrictInteger(endStr,   `range end in field "${fieldName}"`);
    return expandRange(start, end, 1, min, max, `field "${fieldName}"`);
  }

  // Plain integer
  const value = parseStrictInteger(s, `value in field "${fieldName}"`);
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of bounds [${min}, ${max}] in field "${fieldName}"`);
  }
  return [value];
}

function parseField(raw: string, min: number, max: number, fieldName: string): number[] {
  const trimmed = raw.trim();

  if (trimmed === "") {
    throw new Error(`Field "${fieldName}" is empty`);
  }

  const segments = trimmed.split(",");
  const seen = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment, min, max, fieldName);
    for (const v of values) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, received: ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 whitespace-separated fields, got ${parts.length}: "${expression}"`,
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const name = FIELD_NAMES[i];
    const { min, max } = FIELD_RANGES[name];
    try {
      result[name] = parseField(parts[i], min, max, name);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid cron expression at field ${i + 1} ("${name}"): ${msg}`);
    }
  }

  return result;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

export class CronParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CronParseError";
  }
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
] as const;

const DIGITS_ONLY_RE = /^\d+$/;

function parseNonNegativeInteger(raw: string, ctx: string): number {
  if (!DIGITS_ONLY_RE.test(raw)) {
    throw new CronParseError(
      `Expected a non-negative integer but got "${raw}" (${ctx})`,
    );
  }
  const n = parseInt(raw, 10);
  if (!Number.isSafeInteger(n)) {
    throw new CronParseError(
      `Integer "${raw}" is outside the safe integer range (${ctx})`,
    );
  }
  return n;
}

function assertInRange(
  value: number,
  min: number,
  max: number,
  ctx: string,
): void {
  if (value < min || value > max) {
    throw new CronParseError(
      `Value ${value} is out of the valid range [${min}, ${max}] (${ctx})`,
    );
  }
}

function buildRange(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => i + start);
}

function buildStep(
  start: number,
  end: number,
  step: number,
  ctx: string,
): number[] {
  if (step <= 0) {
    throw new CronParseError(
      `Step must be a positive integer, got ${step} (${ctx})`,
    );
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseDashRange(
  raw: string,
  min: number,
  max: number,
  ctx: string,
): [number, number] {
  const dashIdx = raw.indexOf("-");
  if (dashIdx <= 0 || dashIdx === raw.length - 1) {
    throw new CronParseError(
      `Malformed range "${raw}": expected "start-end" with non-empty start and end (${ctx})`,
    );
  }
  const start = parseNonNegativeInteger(raw.slice(0, dashIdx), ctx);
  const end   = parseNonNegativeInteger(raw.slice(dashIdx + 1), ctx);
  assertInRange(start, min, max, ctx);
  assertInRange(end,   min, max, ctx);
  if (start > end) {
    throw new CronParseError(
      `Range start ${start} must not exceed end ${end} (${ctx})`,
    );
  }
  return [start, end];
}

function parseSegment(
  segment: string,
  min: number,
  max: number,
  fieldName: string,
): number[] {
  const s = segment.trim();
  const ctx = `field "${fieldName}", segment "${s}"`;

  if (s.length === 0) {
    throw new CronParseError(
      `Empty segment encountered in field "${fieldName}"`,
    );
  }

  // ── 1. Step notation: "base/step" ─────────────────────────────────────────
  const slashIdx = s.indexOf("/");
  if (slashIdx !== -1) {
    if (s.indexOf("/", slashIdx + 1) !== -1) {
      throw new CronParseError(
        `Multiple "/" separators in "${s}" (${ctx})`,
      );
    }

    const basePart = s.slice(0, slashIdx);
    const stepPart = s.slice(slashIdx + 1);

    if (basePart.length === 0) {
      throw new CronParseError(
        `Missing base before "/" in "${s}" (${ctx})`,
      );
    }
    if (stepPart.length === 0) {
      throw new CronParseError(
        `Missing step value after "/" in "${s}" (${ctx})`,
      );
    }

    const step = parseNonNegativeInteger(stepPart, ctx);
    if (step === 0) {
      throw new CronParseError(
        `Step value must be a positive integer, got 0 (${ctx})`,
      );
    }

    let rangeStart: number;
    let rangeEnd:   number;

    if (basePart === "*") {
      rangeStart = min;
      rangeEnd   = max;
    } else if (basePart.includes("-")) {
      [rangeStart, rangeEnd] = parseDashRange(basePart, min, max, ctx);
    } else {
      rangeStart = parseNonNegativeInteger(basePart, ctx);
      assertInRange(rangeStart, min, max, ctx);
      rangeEnd = max;
    }

    return buildStep(rangeStart, rangeEnd, step, ctx);
  }

  // ── 2. Wildcard ────────────────────────────────────────────────────────────
  if (s === "*") {
    return buildRange(min, max);
  }

  // ── 3. Dash range: "N-M" ──────────────────────────────────────────────────
  if (s.includes("-")) {
    const [start, end] = parseDashRange(s, min, max, ctx);
    return buildRange(start, end);
  }

  // ── 4. Single integer ─────────────────────────────────────────────────────
  const value = parseNonNegativeInteger(s, ctx);
  assertInRange(value, min, max, ctx);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  if (typeof raw !== "string") {
    throw new CronParseError(
      `Field "${name}" must be a string, received ${typeof raw}`,
    );
  }

  const trimmed = raw.trim();
  if (trimmed.length === 0) {
    throw new CronParseError(
      `Field "${name}" must not be empty`,
    );
  }

  const parts = trimmed.split(",");
  const seen  = new Set<number>();

  for (const part of parts) {
    const segment = part.trim();
    if (segment.length === 0) {
      throw new CronParseError(
        `Empty entry in comma-separated list for field "${name}" (expression: "${trimmed}")`,
      );
    }
    for (const v of parseSegment(segment, min, max, name)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new CronParseError(
      `parseCron expects a string, received ${typeof expression}`,
    );
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new CronParseError("Cron expression must not be empty or whitespace-only");
  }

  const rawFields = trimmed.split(/\s+/);

  if (rawFields.length !== 5) {
    throw new CronParseError(
      `Expected exactly 5 whitespace-separated fields, got ${rawFields.length} in: "${trimmed}"`,
    );
  }

  const result = {} as CronExpression;
  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    result[FIELD_CONFIGS[i].name] = parseField(rawFields[i], FIELD_CONFIGS[i]);
  }
  return result;
}

export default parseCron;

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
] as const;

function parseNonNegativeInt(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Invalid integer "${raw}" in ${context} — must be all digits`);
  }
  const n = parseInt(raw, 10);
  if (!isFinite(n)) {
    throw new Error(`Parsed non-finite value from "${raw}" in ${context}`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of valid range [${min}–${max}] in ${context}`);
  }
}

function normalizeValue(value: number, config: FieldConfig): number {
  // dayOfWeek: some cron dialects use 7 as an alias for Sunday (0)
  if (config.name === "dayOfWeek" && value === 7) return 0;
  return value;
}

function parseSinglePart(part: string, config: FieldConfig): number[] {
  const { min, max, name } = config;
  const context = `field "${name}" part "${part}"`;

  if (!part) throw new Error(`Empty segment in ${context}`);

  // Step expression: */n  |  a-b/n  |  a/n
  const stepSepIdx = part.lastIndexOf("/");
  if (stepSepIdx !== -1) {
    const stepStr = part.slice(stepSepIdx + 1);
    const baseStr = part.slice(0, stepSepIdx);

    if (!stepStr) throw new Error(`Missing step value in ${context}`);
    const step = parseNonNegativeInt(stepStr, context);
    if (step === 0) throw new Error(`Step value cannot be 0 in ${context}`);

    let rangeMin: number;
    let rangeMax: number;

    if (baseStr === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (baseStr.includes("-")) {
      const dashIdx = baseStr.indexOf("-");
      rangeMin = parseNonNegativeInt(baseStr.slice(0, dashIdx), context);
      rangeMax = parseNonNegativeInt(baseStr.slice(dashIdx + 1), context);
    } else {
      rangeMin = parseNonNegativeInt(baseStr, context);
      rangeMax = max;
    }

    assertInRange(rangeMin, min, max, context);
    assertInRange(rangeMax, min, max, context);
    if (rangeMin > rangeMax) {
      throw new RangeError(`Range start ${rangeMin} exceeds end ${rangeMax} in ${context}`);
    }

    const values: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      values.push(normalizeValue(v, config));
    }
    return values;
  }

  // Wildcard
  if (part === "*") {
    const values: number[] = [];
    for (let v = min; v <= max; v++) values.push(v);
    return values;
  }

  // Range: a-b
  const dashIdx = part.indexOf("-");
  if (dashIdx !== -1) {
    if (dashIdx === 0 || dashIdx === part.length - 1) {
      throw new Error(`Malformed range "${part}" in ${context}`);
    }
    const rangeMin = parseNonNegativeInt(part.slice(0, dashIdx), context);
    const rangeMax = parseNonNegativeInt(part.slice(dashIdx + 1), context);

    assertInRange(rangeMin, min, max, context);
    assertInRange(rangeMax, min, max, context);
    if (rangeMin > rangeMax) {
      throw new RangeError(`Range start ${rangeMin} exceeds end ${rangeMax} in ${context}`);
    }

    const values: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v++) {
      values.push(normalizeValue(v, config));
    }
    return values;
  }

  // Single numeric value
  const num = parseNonNegativeInt(part, context);
  const normalized = normalizeValue(num, config);
  assertInRange(normalized, min, max, context);
  return [normalized];
}

function parseField(raw: string, config: FieldConfig): number[] {
  const { name } = config;

  if (!raw || raw.trim() === "") {
    throw new Error(`Empty field "${name}"`);
  }

  const parts = raw.split(",");
  if (parts.some((p) => p.trim() === "")) {
    throw new Error(`Trailing or doubled comma in field "${name}": "${raw}"`);
  }

  const valueSet = new Set<number>();
  for (const part of parts) {
    const resolved = parseSinglePart(part.trim(), config);
    for (const v of resolved) valueSet.add(v);
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (expression == null || typeof expression !== "string") {
    throw new TypeError(`parseCron requires a string, got ${expression == null ? "null/undefined" : typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) throw new Error("Cron expression must not be empty or whitespace");

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${trimmed}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    result[config.name] = parseField(fields[i], config);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: unknown };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix = "",
  result: Record<string, Primitive> = {},
  seen = new WeakSet<object>()
): Record<string, Primitive> {
  if (input === null || input === undefined) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (!isPlainObject(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (seen.has(input as object)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix}"`
    );
  }

  seen.add(input as object);

  const keys = Object.keys(input as NestedObject);

  if (keys.length === 0) {
    if (prefix !== "") {
      result[prefix] = {};
    }
    seen.delete(input as object);
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(input, key)) continue;

    const sanitizedKey = String(key);
    const nextPrefix = prefix === "" ? sanitizedKey : `${prefix}.${sanitizedKey}`;
    const value = (input as NestedObject)[key];

    if (isPlainObject(value)) {
      flattenObject(value, nextPrefix, result, seen);
    } else {
      result[nextPrefix] = value as Primitive;
    }
  }

  seen.delete(input as object);
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type LeafValue = Primitive | Date | RegExp | Function | unknown[];
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: LeafValue };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  obj: NestedObject,
  prefix = "",
  seen = new WeakSet<object>()
): FlatObject {
  if (seen.has(obj)) {
    throw new Error(
      `Circular reference detected${prefix ? ` at path: "${prefix}"` : ""}`
    );
  }

  seen.add(obj);
  const result: FlatObject = {};

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const fullKey = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      const nested = flattenObject(value, fullKey, seen);
      Object.assign(result, nested);
    } else {
      // Treat empty objects, arrays, dates, regexps, nulls, primitives as leaves
      result[fullKey] = value as LeafValue;
    }
  }

  // Backtrack: allow the same object reference in sibling branches
  seen.delete(obj);

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type FlattenableValue = Primitive | Date | RegExp | Function | Array<unknown> | Record<string, unknown>;

type FlattenedObject = Record<string, FlattenableValue>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map) return false;
  if (value instanceof Set) return false;
  if (value instanceof WeakMap) return false;
  if (value instanceof WeakSet) return false;
  if (Array.isArray(value)) return false;
  return true;
}

function flattenObject(
  input: unknown,
  maxDepth: number = 100
): FlattenedObject {
  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : typeof input
      }`
    );
  }

  const result: FlattenedObject = {};
  const seen = new WeakSet<object>();

  function recurse(current: Record<string, unknown>, prefix: string, depth: number): void {
    if (depth > maxDepth) {
      throw new RangeError(
        `flattenObject exceeded maximum depth of ${maxDepth}. Possible circular structure or deeply nested object.`
      );
    }

    if (seen.has(current)) {
      throw new TypeError(
        `flattenObject detected a circular reference at path: "${prefix}"`
      );
    }

    seen.add(current);

    const keys = Object.keys(current);

    if (keys.length === 0) {
      if (prefix !== "") {
        result[prefix] = current as FlattenableValue;
      }
      seen.delete(current);
      return;
    }

    for (const key of keys) {
      if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

      const safeKey = String(key);
      const nextPrefix = prefix === "" ? safeKey : `${prefix}.${safeKey}`;
      const value: unknown = current[key];

      if (isPlainObject(value)) {
        recurse(value as Record<string, unknown>, nextPrefix, depth + 1);
      } else {
        result[nextPrefix] = value as FlattenableValue;
      }
    }

    seen.delete(current);
  }

  recurse(input, "", 0);
  return result;
}

export default flattenObject;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
  readonly name: string;
}

const FIELD_CONFIGS = {
  minute:     { min: 0,  max: 59, name: "minute"     },
  hour:       { min: 0,  max: 23, name: "hour"       },
  dayOfMonth: { min: 1,  max: 31, name: "dayOfMonth" },
  month:      { min: 1,  max: 12, name: "month"      },
  dayOfWeek:  { min: 0,  max: 7,  name: "dayOfWeek"  },
} as const satisfies Record<keyof CronFields, FieldConfig>;

const FIELD_ORDER: ReadonlyArray<keyof CronFields> = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

const INTEGER_PATTERN = /^\d+$/;

function parseIntStrict(raw: string): number | null {
  if (!INTEGER_PATTERN.test(raw)) return null;
  const n = Number(raw);
  return Number.isInteger(n) && n <= Number.MAX_SAFE_INTEGER ? n : null;
}

function assertInRange(value: number, config: FieldConfig): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} is out of range [${config.min}–${config.max}] for field "${config.name}"`,
    );
  }
}

function buildRange(start: number, end: number, step: number, config: FieldConfig): number[] {
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in field "${config.name}"`,
    );
  }
  if (step < 1) {
    throw new RangeError(
      `Step must be ≥ 1, got ${step} in field "${config.name}"`,
    );
  }
  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(v);
  }
  return values;
}

function parseToken(token: string, config: FieldConfig): number[] {
  if (!token) {
    throw new SyntaxError(`Empty token in field "${config.name}"`);
  }

  // Step notation: base/step  (e.g. "*/15", "1-5/2", "3/10")
  if (token.includes("/")) {
    const slashIdx = token.indexOf("/");
    const baseStr = token.slice(0, slashIdx);
    const stepStr = token.slice(slashIdx + 1);

    if (!baseStr || !stepStr) {
      throw new SyntaxError(`Malformed step expression "${token}" in field "${config.name}"`);
    }

    const step = parseIntStrict(stepStr);
    if (step === null || step < 1) {
      throw new SyntaxError(
        `Invalid step value "${stepStr}" in field "${config.name}": must be a positive integer`,
      );
    }

    if (baseStr === "*") {
      return buildRange(config.min, config.max, step, config);
    }

    if (baseStr.includes("-")) {
      const [lo, hi] = parseRangeParts(baseStr, config);
      return buildRange(lo, hi, step, config);
    }

    const start = parseIntStrict(baseStr);
    if (start === null) {
      throw new SyntaxError(
        `Invalid start value "${baseStr}" in step expression "${token}" in field "${config.name}"`,
      );
    }
    assertInRange(start, config);
    return buildRange(start, config.max, step, config);
  }

  // Wildcard
  if (token === "*") {
    return buildRange(config.min, config.max, 1, config);
  }

  // Range: "lo-hi"
  if (token.includes("-")) {
    const [lo, hi] = parseRangeParts(token, config);
    return buildRange(lo, hi, 1, config);
  }

  // Single integer
  const value = parseIntStrict(token);
  if (value === null) {
    throw new SyntaxError(
      `Invalid value "${token}" in field "${config.name}": expected an integer`,
    );
  }
  assertInRange(value, config);
  return [value];
}

function parseRangeParts(raw: string, config: FieldConfig): [number, number] {
  const dashIdx = raw.indexOf("-");
  if (dashIdx <= 0 || dashIdx === raw.length - 1) {
    throw new SyntaxError(`Malformed range "${raw}" in field "${config.name}"`);
  }

  const loStr = raw.slice(0, dashIdx);
  const hiStr = raw.slice(dashIdx + 1);

  // Guard against "1-2-3" style inputs
  if (hiStr.includes("-")) {
    throw new SyntaxError(
      `Ambiguous range "${raw}" in field "${config.name}": too many hyphens`,
    );
  }

  const lo = parseIntStrict(loStr);
  const hi = parseIntStrict(hiStr);

  if (lo === null || hi === null) {
    throw new SyntaxError(
      `Non-integer bounds in range "${raw}" in field "${config.name}"`,
    );
  }

  assertInRange(lo, config);
  assertInRange(hi, config);

  return [lo, hi];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (typeof raw !== "string" || raw.trim() === "") {
    throw new SyntaxError(`Missing or empty value for field "${config.name}"`);
  }

  const segments = raw.split(",");
  if (segments.some((s) => s.trim() === "")) {
    throw new SyntaxError(
      `Trailing or consecutive commas in field "${config.name}": "${raw}"`,
    );
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    const values = parseToken(segment.trim(), config);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: unknown): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${expression === null ? "null" : typeof expression}`,
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 whitespace-separated fields; got ${parts.length} in "${expression}"`,
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(parts[i], FIELD_CONFIGS[fieldName]);
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronFields;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 7  }, // 7 is alias for Sunday (0)
] as const;

function buildRange(start: number, end: number): number[] {
  if (start > end) return [];
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function buildRangeWithStep(start: number, end: number, step: number): number[] {
  if (step <= 0) throw new RangeError(`Step must be a positive integer, got ${step}`);
  if (start > end) return [];
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseStepSuffix(raw: string, fieldName: string): number {
  const step = Number(raw);
  if (!Number.isInteger(step) || step <= 0) {
    throw new RangeError(
      `Step value must be a positive integer in field "${fieldName}", got "${raw}"`
    );
  }
  return step;
}

function parseBoundedInt(raw: string, min: number, max: number, fieldName: string, role: string): number {
  const n = Number(raw);
  if (!Number.isInteger(n) || raw.trim() === "") {
    throw new TypeError(`Non-integer ${role} "${raw}" in field "${fieldName}"`);
  }
  if (n < min || n > max) {
    throw new RangeError(
      `${role} ${n} is out of bounds [${min}, ${max}] in field "${fieldName}"`
    );
  }
  return n;
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  if (segment === "") {
    throw new SyntaxError(`Empty segment encountered in field "${fieldName}"`);
  }

  // Step with wildcard base: */n
  if (segment.startsWith("*/")) {
    const stepRaw = segment.slice(2);
    if (stepRaw === "") {
      throw new SyntaxError(`Missing step value after "*/" in field "${fieldName}"`);
    }
    const step = parseStepSuffix(stepRaw, fieldName);
    return buildRangeWithStep(min, max, step);
  }

  // Range with optional step: start-end[/step]
  if (segment.includes("-")) {
    const slashIdx = segment.indexOf("/");
    const rangePart = slashIdx === -1 ? segment : segment.slice(0, slashIdx);
    const stepPart  = slashIdx === -1 ? null     : segment.slice(slashIdx + 1);

    const dashParts = rangePart.split("-");
    if (dashParts.length !== 2) {
      throw new SyntaxError(`Invalid range expression "${segment}" in field "${fieldName}"`);
    }

    const start = parseBoundedInt(dashParts[0], min, max, fieldName, "Range start");
    const end   = parseBoundedInt(dashParts[1], min, max, fieldName, "Range end");

    if (start > end) {
      throw new RangeError(
        `Range start (${start}) must not exceed range end (${end}) in field "${fieldName}"`
      );
    }

    if (stepPart !== null) {
      if (stepPart === "") {
        throw new SyntaxError(`Missing step value after "/" in field "${fieldName}"`);
      }
      const step = parseStepSuffix(stepPart, fieldName);
      return buildRangeWithStep(start, end, step);
    }

    return buildRange(start, end);
  }

  // Plain number with optional step: n/step
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(`Invalid step expression "${segment}" in field "${fieldName}"`);
    }
    const start = parseBoundedInt(slashParts[0], min, max, fieldName, "Value");
    if (slashParts[1] === "") {
      throw new SyntaxError(`Missing step value after "/" in field "${fieldName}"`);
    }
    const step = parseStepSuffix(slashParts[1], fieldName);
    return buildRangeWithStep(start, max, step);
  }

  // Plain integer
  const value = parseBoundedInt(segment, min, max, fieldName, "Value");
  return [value];
}

function parseField(raw: string, min: number, max: number, fieldName: string): number[] {
  if (raw === "") {
    throw new SyntaxError(`Field "${fieldName}" is empty`);
  }

  const segments = raw.split(",");
  const accumulated = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    const values = parseSegment(trimmed, min, max, fieldName);
    for (const v of values) {
      accumulated.add(v);
    }
  }

  return Array.from(accumulated).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    const rawField = parts[i];

    if (rawField === undefined || rawField === "") {
      throw new SyntaxError(`Field "${config.name}" at position ${i} is missing`);
    }

    let values = parseField(rawField, config.min, config.max, config.name);

    // Normalize dayOfWeek: 7 is an alias for Sunday (0)
    if (config.name === "dayOfWeek") {
      const normalized = new Set<number>(values.map(d => (d === 7 ? 0 : d)));
      values = Array.from(normalized).sort((a, b) => a - b);
    }

    result[config.name] = values;
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

// dayOfWeek allows 0-7 as input; 7 is a Sunday alias for 0 and gets normalized
const FIELD_CONFIGS: Readonly<Record<FieldName, FieldConfig>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
} as const;

const FIELD_ORDER: readonly FieldName[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
] as const;

function assertInteger(raw: string, fieldName: FieldName): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new RangeError(
      `Field "${fieldName}": "${trimmed}" is not a valid non-negative integer`
    );
  }
  return parseInt(trimmed, 10);
}

function assertInRange(
  value: number,
  config: FieldConfig,
  fieldName: FieldName,
  context: string
): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Field "${fieldName}": value ${value} (in "${context}") is outside ` +
      `allowed range [${config.min}, ${config.max}]`
    );
  }
}

function expandRange(
  start: number,
  end: number,
  step: number,
  config: FieldConfig,
  fieldName: FieldName,
  context: string
): number[] {
  if (step < 1) {
    throw new RangeError(
      `Field "${fieldName}": step value ${step} must be >= 1 (in "${context}")`
    );
  }
  assertInRange(start, config, fieldName, context);
  assertInRange(end, config, fieldName, context);

  if (start > end) {
    throw new RangeError(
      `Field "${fieldName}": range start ${start} exceeds end ${end} (in "${context}")`
    );
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(
  segment: string,
  config: FieldConfig,
  fieldName: FieldName
): number[] {
  const s = segment.trim();
  if (s === "") {
    throw new SyntaxError(
      `Field "${fieldName}": encountered an empty segment — possible trailing or double comma`
    );
  }

  // Step expression:  * / n  or  start-end/n  or  start/n
  if (s.includes("/")) {
    const slashIdx = s.indexOf("/");
    const afterLastSlash = s.slice(slashIdx + 1);
    if (afterLastSlash.includes("/")) {
      throw new SyntaxError(
        `Field "${fieldName}": multiple "/" separators in segment "${s}"`
      );
    }
    const step = assertInteger(afterLastSlash, fieldName);
    const rangePart = s.slice(0, slashIdx);

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = config.min;
      end   = config.max;
    } else if (rangePart.includes("-")) {
      const dashIdx = rangePart.indexOf("-");
      // Protect against negative number smuggled in via "--" or "-5"
      if (dashIdx === 0) {
        throw new SyntaxError(
          `Field "${fieldName}": segment "${s}" starts with "-", which is not a valid range`
        );
      }
      start = assertInteger(rangePart.slice(0, dashIdx), fieldName);
      end   = assertInteger(rangePart.slice(dashIdx + 1), fieldName);
    } else {
      start = assertInteger(rangePart, fieldName);
      end   = config.max;
    }

    return expandRange(start, end, step, config, fieldName, s);
  }

  // Bare wildcard
  if (s === "*") {
    return expandRange(config.min, config.max, 1, config, fieldName, s);
  }

  // Range expression:  start-end
  if (s.includes("-")) {
    const dashIdx = s.indexOf("-");
    if (dashIdx === 0) {
      throw new SyntaxError(
        `Field "${fieldName}": segment "${s}" starts with "-", which is not a valid range`
      );
    }
    const start = assertInteger(s.slice(0, dashIdx), fieldName);
    const end   = assertInteger(s.slice(dashIdx + 1), fieldName);
    return expandRange(start, end, 1, config, fieldName, s);
  }

  // Single numeric value
  const value = assertInteger(s, fieldName);
  assertInRange(value, config, fieldName, s);
  return [value];
}

function parseField(
  raw: string,
  config: FieldConfig,
  fieldName: FieldName
): number[] {
  const trimmed = raw.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Field "${fieldName}" is empty`);
  }

  const segments = trimmed.split(",");
  const accumulated = new Set<number>();

  for (const segment of segments) {
    for (const value of parseSegment(segment, config, fieldName)) {
      accumulated.add(value);
    }
  }

  // Normalize dayOfWeek: 7 is a Sunday alias — fold it into 0
  if (fieldName === "dayOfWeek") {
    if (accumulated.has(7)) {
      accumulated.delete(7);
      accumulated.add(0);
    }
  }

  return Array.from(accumulated).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string but received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 space-separated fields, ` +
      `but got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(parts[i], FIELD_CONFIGS[fieldName], fieldName);
  }
  return result;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

export class CronParseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "CronParseError";
  }
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
] as const;

const DIGITS_ONLY_RE = /^\d+$/;

function parseNonNegativeInteger(raw: string, ctx: string): number {
  if (!DIGITS_ONLY_RE.test(raw)) {
    throw new CronParseError(`Expected a non-negative integer but got "${raw}" (${ctx})`);
  }
  const n = parseInt(raw, 10);
  if (!Number.isSafeInteger(n)) {
    throw new CronParseError(`Integer "${raw}" is outside the safe integer range (${ctx})`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, ctx: string): void {
  if (value < min || value > max) {
    throw new CronParseError(`Value ${value} is out of the valid range [${min}, ${max}] (${ctx})`);
  }
}

function buildRange(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => i + start);
}

function buildStep(start: number, end: number, step: number, ctx: string): number[] {
  if (step <= 0) {
    throw new CronParseError(`Step must be a positive integer, got ${step} (${ctx})`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseDashRange(raw: string, min: number, max: number, ctx: string): [number, number] {
  const dashIdx = raw.indexOf("-");
  if (dashIdx <= 0 || dashIdx === raw.length - 1) {
    throw new CronParseError(
      `Malformed range "${raw}": expected "start-end" with non-empty start and end (${ctx})`
    );
  }
  const start = parseNonNegativeInteger(raw.slice(0, dashIdx), ctx);
  const end   = parseNonNegativeInteger(raw.slice(dashIdx + 1), ctx);
  assertInRange(start, min, max, ctx);
  assertInRange(end,   min, max, ctx);
  if (start > end) {
    throw new CronParseError(`Range start ${start} must not exceed end ${end} (${ctx})`);
  }
  return [start, end];
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  const s = segment.trim();
  const ctx = `field "${fieldName}", segment "${s}"`;

  if (s.length === 0) {
    throw new CronParseError(`Empty segment encountered in field "${fieldName}"`);
  }

  const slashIdx = s.indexOf("/");
  if (slashIdx !== -1) {
    if (s.indexOf("/", slashIdx + 1) !== -1) {
      throw new CronParseError(`Multiple "/" separators in "${s}" (${ctx})`);
    }
    const basePart = s.slice(0, slashIdx);
    const stepPart = s.slice(slashIdx + 1);
    if (basePart.length === 0) throw new CronParseError(`Missing base before "/" in "${s}" (${ctx})`);
    if (stepPart.length === 0) throw new CronParseError(`Missing step value after "/" in "${s}" (${ctx})`);

    const step = parseNonNegativeInteger(stepPart, ctx);
    if (step === 0) throw new CronParseError(`Step value must be a positive integer, got 0 (${ctx})`);

    let rangeStart: number, rangeEnd: number;
    if (basePart === "*") {
      rangeStart = min; rangeEnd = max;
    } else if (basePart.includes("-")) {
      [rangeStart, rangeEnd] = parseDashRange(basePart, min, max, ctx);
    } else {
      rangeStart = parseNonNegativeInteger(basePart, ctx);
      assertInRange(rangeStart, min, max, ctx);
      rangeEnd = max;
    }
    return buildStep(rangeStart, rangeEnd, step, ctx);
  }

  if (s === "*") return buildRange(min, max);

  if (s.includes("-")) {
    const [start, end] = parseDashRange(s, min, max, ctx);
    return buildRange(start, end);
  }

  const value = parseNonNegativeInteger(s, ctx);
  assertInRange(value, min, max, ctx);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  const { name, min, max } = config;
  if (typeof raw !== "string") throw new CronParseError(`Field "${name}" must be a string`);
  const trimmed = raw.trim();
  if (trimmed.length === 0) throw new CronParseError(`Field "${name}" must not be empty`);

  const parts = trimmed.split(",");
  const seen  = new Set<number>();
  for (const part of parts) {
    const segment = part.trim();
    if (segment.length === 0) {
      throw new CronParseError(`Empty entry in comma-separated list for field "${name}"`);
    }
    for (const v of parseSegment(segment, min, max, name)) seen.add(v);
  }
  return Array.from(seen).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new CronParseError(`parseCron expects a string, received ${typeof expression}`);
  }
  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new CronParseError("Cron expression must not be empty or whitespace-only");
  }
  const rawFields = trimmed.split(/\s+/);
  if (rawFields.length !== 5) {
    throw new CronParseError(
      `Expected exactly 5 whitespace-separated fields, got ${rawFields.length} in: "${trimmed}"`
    );
  }
  const result = {} as CronExpression;
  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    result[FIELD_CONFIGS[i].name] = parseField(rawFields[i], FIELD_CONFIGS[i]);
  }
  return result;
}

export default parseCron;

type FlatValue = string | number | boolean | null | undefined | symbol | bigint | unknown[] | object;

function isTraversable(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  // Only traverse plain objects — not Date, RegExp, Map, Set, Array, etc.
  return proto === Object.prototype || proto === null;
}

function flatten(
  obj: Record<string, unknown>,
  prefix: string,
  result: Record<string, FlatValue>,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key "${prefix || "(root)"}"`
    );
  }

  const keys = Object.keys(obj);

  // Empty plain object with a prefix — preserve as a leaf so the key isn't lost
  if (keys.length === 0 && prefix !== "") {
    result[prefix] = obj;
    return;
  }

  ancestors.add(obj);

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value = obj[key];
    const dotKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isTraversable(value)) {
      flatten(value as Record<string, unknown>, dotKey, result, ancestors);
    } else {
      result[dotKey] = value as FlatValue;
    }
  }

  ancestors.delete(obj);
}

export default function flattenObject(
  obj: Record<string, unknown>
): Record<string, FlatValue> {
  if (obj === null || typeof obj !== "object") {
    throw new TypeError(`Expected a plain object, got ${obj === null ? "null" : typeof obj}`);
  }

  if (!isTraversable(obj)) {
    throw new TypeError("Expected a plain object, not a built-in class instance");
  }

  const result: Record<string, FlatValue> = {};
  flatten(obj, "", result, new WeakSet());
  return result;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: string;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  },  // 0 and 7 both represent Sunday
] as const satisfies readonly FieldConfig[];

/**
 * Strict integer parser — rejects partial matches like "5abc".
 */
function parseIntStrict(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`parseCron: "${raw}" is not a valid non-negative integer (in ${context})`);
  }
  const value = Number(trimmed);
  if (!Number.isSafeInteger(value)) {
    throw new Error(`parseCron: "${raw}" exceeds safe integer bounds (in ${context})`);
  }
  return value;
}

function assertInRange(value: number, config: FieldConfig, source: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `parseCron: value ${value} is out of range [${config.min}–${config.max}] ` +
      `for field "${config.name}" (from "${source}")`
    );
  }
}

function buildRange(start: number, end: number): number[] {
  if (start > end) {
    throw new RangeError(
      `parseCron: range start (${start}) must be ≤ range end (${end})`
    );
  }
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const ctx = `${config.name} segment "${segment}"`;

  // ── Step value: */n  |  a-b/n  |  a/n ──────────────────────────────────────
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const rangePart = segment.slice(0, slashIdx);
    const stepPart  = segment.slice(slashIdx + 1);

    if (stepPart === "" || stepPart.includes("/")) {
      throw new Error(`parseCron: malformed step expression in ${ctx}`);
    }

    const step = parseIntStrict(stepPart, ctx);
    if (step === 0) {
      throw new RangeError(`parseCron: step value must be ≥ 1 in ${ctx}`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = config.min;
      end   = config.max;
    } else if (rangePart.includes("-")) {
      const dashIdx  = rangePart.indexOf("-");
      start = parseIntStrict(rangePart.slice(0, dashIdx), ctx);
      end   = parseIntStrict(rangePart.slice(dashIdx + 1), ctx);
      assertInRange(start, config, segment);
      assertInRange(end,   config, segment);
    } else {
      start = parseIntStrict(rangePart, ctx);
      assertInRange(start, config, segment);
      end = config.max;
    }

    if (start > end) {
      throw new RangeError(
        `parseCron: step range start (${start}) > end (${end}) in ${ctx}`
      );
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // ── Wildcard ─────────────────────────────────────────────────────────────────
  if (segment === "*") {
    return buildRange(config.min, config.max);
  }

  // ── Range: a-b ───────────────────────────────────────────────────────────────
  if (segment.includes("-")) {
    const dashIdx = segment.indexOf("-");
    const start   = parseIntStrict(segment.slice(0, dashIdx), ctx);
    const end     = parseIntStrict(segment.slice(dashIdx + 1), ctx);
    assertInRange(start, config, segment);
    assertInRange(end,   config, segment);
    return buildRange(start, end);
  }

  // ── Single value ─────────────────────────────────────────────────────────────
  const value = parseIntStrict(segment, ctx);
  assertInRange(value, config, segment);
  return [value];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (typeof field !== "string" || field.trim() === "") {
    throw new Error(
      `parseCron: field "${config.name}" must be a non-empty string`
    );
  }

  const trimmed = field.trim();

  // Comma-separated list — each part is parsed independently, results merged.
  if (trimmed.includes(",")) {
    const parts = trimmed.split(",");
    if (parts.some((p) => p.trim() === "")) {
      throw new Error(
        `parseCron: empty segment in comma list for field "${config.name}"`
      );
    }
    const seen = new Set<number>();
    for (const part of parts) {
      for (const v of parseSegment(part.trim(), config)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSegment(trimmed, config);
}

export function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron: expected a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new Error("parseCron: expression must not be empty");
  }

  // Split on any run of whitespace — guards against tabs, multiple spaces, etc.
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `parseCron: expected exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
      `received ${fields.length}: "${trimmed}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour:       parseField(hourRaw,   FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domRaw,    FIELD_CONFIGS[2]),
    month:      parseField(monthRaw,  FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dowRaw,    FIELD_CONFIGS[4]),
  };
}

export default parseCron;

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof ParsedCron;

interface FieldConfig {
  readonly min: number;
  readonly max: number;
  /** Maximum value accepted as valid input (may differ from expansion max). */
  readonly inputMax: number;
}

const FIELD_ORDER: readonly CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

const FIELD_CONFIGS: Readonly<Record<CronField, FieldConfig>> = {
  minute:     { min: 0,  max: 59, inputMax: 59 },
  hour:       { min: 0,  max: 23, inputMax: 23 },
  dayOfMonth: { min: 1,  max: 31, inputMax: 31 },
  month:      { min: 1,  max: 12, inputMax: 12 },
  // dayOfWeek: 0–6 canonical; 7 is a widely accepted alias for Sunday (0)
  dayOfWeek:  { min: 0,  max: 6,  inputMax: 7  },
} as const;

// ---------------------------------------------------------------------------
// Primitive helpers
// ---------------------------------------------------------------------------

function parseNonNegativeInt(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new RangeError(
      `Expected a non-negative integer for ${context}, got: "${raw}"`
    );
  }
  const n = Number(raw);
  if (!Number.isSafeInteger(n)) {
    throw new RangeError(`Numeric overflow for ${context}: "${raw}"`);
  }
  return n;
}

function assertInRange(
  value: number,
  min: number,
  max: number,
  context: string
): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of the valid range [${min}, ${max}] for ${context}`
    );
  }
}

function buildRange(start: number, end: number, step: number): number[] {
  if (!Number.isInteger(step) || step < 1) {
    throw new RangeError(`Step must be a positive integer, got ${step}`);
  }
  if (start > end) {
    throw new RangeError(
      `Range start (${start}) must be ≤ range end (${end})`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

/**
 * Normalise a raw value for a field. Specifically, dayOfWeek "7" is an alias
 * for 0 (both represent Sunday in traditional cron).
 */
function normalise(value: number, field: CronField): number {
  if (field === "dayOfWeek" && value === 7) return 0;
  return value;
}

// ---------------------------------------------------------------------------
// Token-level parser
// ---------------------------------------------------------------------------

/**
 * Parse a single cron token (no commas) and return the set of resolved values.
 * Handles: `*`, `n`, `n-m`, `* /step`, `n/step`, `n-m/step`.
 */
function parseToken(
  token: string,
  config: FieldConfig,
  field: CronField
): number[] {
  const { min, max, inputMax } = config;

  // ── Step expressions (contain '/') ─────────────────────────────────────
  if (token.includes("/")) {
    const slashCount = (token.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new SyntaxError(
        `Invalid step expression "${token}" for ${field}: expected exactly one '/'`
      );
    }

    const slashIdx = token.indexOf("/");
    const left = token.slice(0, slashIdx);
    const right = token.slice(slashIdx + 1);

    if (!right || right === "") {
      throw new SyntaxError(
        `Missing step value after '/' in "${token}" for ${field}`
      );
    }
    const step = parseNonNegativeInt(right, `step in "${token}" (${field})`);
    if (step < 1) {
      throw new RangeError(
        `Step value must be ≥ 1 in "${token}" for ${field}, got ${step}`
      );
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (left === "*") {
      rangeStart = min;
      rangeEnd = max; // wildcard always expands to the canonical max
    } else if (left.includes("-")) {
      const dashParts = left.split("-");
      if (dashParts.length !== 2 || dashParts[0] === "" || dashParts[1] === "") {
        throw new SyntaxError(
          `Invalid range "${left}" in step expression for ${field}`
        );
      }
      rangeStart = normalise(
        parseNonNegativeInt(dashParts[0], `range-start in "${token}" (${field})`),
        field
      );
      rangeEnd = normalise(
        parseNonNegativeInt(dashParts[1], `range-end in "${token}" (${field})`),
        field
      );
      assertInRange(rangeStart, min, inputMax, `range-start for ${field}`);
      assertInRange(rangeEnd,   min, inputMax, `range-end for ${field}`);
    } else {
      // `n/step` — start at n, step to canonical max
      rangeStart = normalise(
        parseNonNegativeInt(left, `start-value in "${token}" (${field})`),
        field
      );
      assertInRange(rangeStart, min, inputMax, `start-value for ${field}`);
      rangeEnd = max;
    }

    if (rangeStart > rangeEnd) {
      throw new RangeError(
        `Range start (${rangeStart}) must be ≤ range end (${rangeEnd}) in "${token}" for ${field}`
      );
    }

    return buildRange(rangeStart, rangeEnd, step).map((v) => normalise(v, field));
  }

  // ── Range expressions (contain '-', no '/') ─────────────────────────────
  if (token.includes("-")) {
    const dashParts = token.split("-");
    if (dashParts.length !== 2 || dashParts[0] === "" || dashParts[1] === "") {
      throw new SyntaxError(
        `Invalid range expression "${token}" for ${field}: expected "n-m"`
      );
    }
    const start = parseNonNegativeInt(dashParts[0], `range-start for ${field}`);
    const end   = parseNonNegativeInt(dashParts[1], `range-end for ${field}`);

    assertInRange(start, min, inputMax, `range-start for ${field}`);
    assertInRange(end,   min, inputMax, `range-end for ${field}`);

    // Normalise after validation so that "5-7" on dayOfWeek → [5, 6, 0]
    // rather than refusing a perfectly legal expression.
    const rawValues = buildRange(start, end, 1);
    return rawValues.map((v) => normalise(v, field));
  }

  // ── Wildcard ─────────────────────────────────────────────────────────────
  if (token === "*") {
    return buildRange(min, max, 1);
  }

  // ── Single integer ────────────────────────────────────────────────────────
  const value = parseNonNegativeInt(token, field);
  assertInRange(value, min, inputMax, field);
  return [normalise(value, field)];
}

// ---------------------------------------------------------------------------
// Field-level parser
// ---------------------------------------------------------------------------

function parseField(
  expression: string,
  config: FieldConfig,
  field: CronField
): number[] {
  if (expression === "" || expression.trim() === "") {
    throw new SyntaxError(`Empty field expression for "${field}"`);
  }

  const tokens = expression.split(",");
  if (tokens.some((t) => t === "")) {
    throw new SyntaxError(
      `Trailing or consecutive commas in expression "${expression}" for ${field}`
    );
  }

  const valueSet = new Set<number>();

  for (const token of tokens) {
    const trimmed = token.trim();
    if (trimmed === "") {
      throw new SyntaxError(
        `Blank token found in expression "${expression}" for ${field}`
      );
    }
    for (const v of parseToken(trimmed, config, field)) {
      valueSet.add(v);
    }
  }

  if (valueSet.size === 0) {
    throw new RangeError(
      `Field "${field}" resolved to an empty value set from expression "${expression}"`
    );
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Parse a 5-field cron expression into a structured object containing arrays
 * of all valid values for each field.
 *
 * Supported field syntax:
 *  - `*`        — wildcard (all valid values)
 *  - `n`        — single integer
 *  - `n-m`      — inclusive range
 *  - `* /step`   — every <step> starting from the field minimum
 *  - `n/step`   — every <step> starting from n
 *  - `n-m/step` — every <step> within the range n–m
 *  - `a,b,...`  — comma-separated list of any of the above
 *
 * Valid ranges:
 *  - minute:     0–59
 *  - hour:       0–23
 *  - dayOfMonth: 1–31
 *  - month:      1–12
 *  - dayOfWeek:  0–6  (7 is accepted as an alias for 0 / Sunday)
 *
 * @throws {TypeError}   if `expression` is not a string
 * @throws {SyntaxError} if the expression cannot be parsed
 * @throws {RangeError}  if any value falls outside its valid range
 */
export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  // Split on any run of whitespace so that extra spaces don't cause failures.
  const rawFields = trimmed.split(/\s+/);

  if (rawFields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must contain exactly 5 whitespace-separated fields, ` +
      `got ${rawFields.length}: "${expression}"`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(rawFields[i], FIELD_CONFIGS[field], field);
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronFields;
  readonly min: number;
  readonly max: number;
  /** Some implementations allow 7 as alias for 0 (Sunday) in dayOfWeek */
  readonly aliasMax?: number;
}

const FIELD_CONFIGS: readonly [FieldConfig, FieldConfig, FieldConfig, FieldConfig, FieldConfig] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 6, aliasMax: 7 },
] as const;

function assertBoundedInteger(
  value: number,
  lo: number,
  hi: number,
  label: string
): void {
  if (!Number.isInteger(value) || value < lo || value > hi) {
    throw new RangeError(
      `Value ${value} is out of valid range [${lo}, ${hi}] for field "${label}"`
    );
  }
}

function parseInteger(raw: string, fieldName: string): number {
  // Reject anything that isn't a clean decimal integer string.
  // Rejects empty strings, floats, hex literals, leading/trailing whitespace, etc.
  if (!/^\d+$/.test(raw)) {
    throw new SyntaxError(
      `Expected a non-negative integer but got "${raw}" in field "${fieldName}"`
    );
  }
  const n = Number(raw);
  if (!Number.isInteger(n)) {
    // Extremely large numbers may lose precision — guard against that.
    throw new RangeError(
      `Integer "${raw}" cannot be represented safely in field "${fieldName}"`
    );
  }
  return n;
}

function expandRange(start: number, end: number, step: number): number[] {
  if (start > end) {
    throw new RangeError(`Range start ${start} must not exceed end ${end}`);
  }
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer, got ${step}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

/**
 * Parse a single, non-comma-containing segment such as:
 *   "*", "5", "1-5", "* /15", "0-30/5"
 */
function parseSegment(segment: string, config: FieldConfig): number[] {
  if (typeof segment !== "string" || segment.length === 0) {
    throw new SyntaxError(`Empty segment in field "${config.name}"`);
  }

  const effectiveMax = config.aliasMax ?? config.max;

  // ── Step expression: <range-or-wildcard>/<step> ──────────────────────────
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const rangePart = segment.slice(0, slashIdx);
    const stepPart  = segment.slice(slashIdx + 1);

    if (rangePart.length === 0 || stepPart.length === 0) {
      throw new SyntaxError(
        `Malformed step expression "${segment}" in field "${config.name}"`
      );
    }

    const step = parseInteger(stepPart, config.name);
    if (step === 0) {
      throw new RangeError(`Step value must be >= 1 in field "${config.name}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = config.min;
      end   = config.max; // intentionally use max, not aliasMax, for wildcard expansions
    } else if (rangePart.includes("-")) {
      const dashIdx  = rangePart.indexOf("-");
      const startStr = rangePart.slice(0, dashIdx);
      const endStr   = rangePart.slice(dashIdx + 1);

      if (startStr.length === 0 || endStr.length === 0) {
        throw new SyntaxError(
          `Malformed range "${rangePart}" in field "${config.name}"`
        );
      }

      start = parseInteger(startStr, config.name);
      end   = parseInteger(endStr,   config.name);
    } else {
      // "<n>/step" — start at n, run to field max
      start = parseInteger(rangePart, config.name);
      end   = effectiveMax;
    }

    assertBoundedInteger(start, config.min, effectiveMax, config.name);
    assertBoundedInteger(end,   config.min, effectiveMax, config.name);

    return expandRange(start, end, step);
  }

  // ── Range: <start>-<end> ─────────────────────────────────────────────────
  if (segment.includes("-")) {
    const dashIdx  = segment.indexOf("-");
    const startStr = segment.slice(0, dashIdx);
    const endStr   = segment.slice(dashIdx + 1);

    if (startStr.length === 0 || endStr.length === 0) {
      throw new SyntaxError(
        `Malformed range "${segment}" in field "${config.name}"`
      );
    }

    const start = parseInteger(startStr, config.name);
    const end   = parseInteger(endStr,   config.name);

    assertBoundedInteger(start, config.min, effectiveMax, config.name);
    assertBoundedInteger(end,   config.min, effectiveMax, config.name);

    return expandRange(start, end, 1);
  }

  // ── Wildcard ─────────────────────────────────────────────────────────────
  if (segment === "*") {
    return expandRange(config.min, config.max, 1);
  }

  // ── Plain integer ────────────────────────────────────────────────────────
  const n = parseInteger(segment, config.name);
  assertBoundedInteger(n, config.min, effectiveMax, config.name);
  return [n];
}

/**
 * Parse a full cron field value, which may be a comma-separated list of
 * segments: e.g. "1,3,5-9,* /15"
 */
function parseField(rawField: string, config: FieldConfig): number[] {
  if (typeof rawField !== "string" || rawField.trim().length === 0) {
    throw new SyntaxError(`Empty or missing value for cron field "${config.name}"`);
  }

  const parts = rawField.split(",");
  const accumulated = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed.length === 0) {
      throw new SyntaxError(
        `Empty element in comma-separated list for field "${config.name}"`
      );
    }

    const values = parseSegment(trimmed, config);
    for (const v of values) {
      accumulated.add(v);
    }
  }

  // Normalise alias: for dayOfWeek, 7 is treated as 0 (both mean Sunday).
  if (config.aliasMax !== undefined && accumulated.has(config.aliasMax)) {
    accumulated.delete(config.aliasMax);
    accumulated.add(config.min); // config.min === 0 for dayOfWeek
  }

  if (accumulated.size === 0) {
    throw new RangeError(
      `Cron field "${config.name}" expanded to an empty set — check the expression`
    );
  }

  return Array.from(accumulated).sort((a, b) => a - b);
}

/**
 * Parse a 5-field cron expression into arrays of concrete values.
 *
 * Supports: wildcards (*), numbers (5), ranges (1-5),
 *           step values (*\/15 or 1-10/2), and comma-separated lists.
 *
 * @throws {TypeError}   if the argument is not a string
 * @throws {SyntaxError} if the expression is structurally malformed
 * @throws {RangeError}  if any value falls outside the valid field range
 */
export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError("Cron expression must not be an empty string");
  }

  // Collapse all whitespace variants (tabs, multiple spaces) between fields.
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 space-separated fields, ` +
      `but got ${fields.length} in: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour:       parseField(hourRaw,   FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domRaw,    FIELD_CONFIGS[2]),
    month:      parseField(monthRaw,  FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dowRaw,    FIELD_CONFIGS[4]),
  };
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: string;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
] as const;

function parseIntStrict(value: string, context: string): number {
  if (!/^\d+$/.test(value)) {
    throw new RangeError(`Invalid numeric value "${value}" in ${context}`);
  }
  const n = parseInt(value, 10);
  if (!Number.isFinite(n)) {
    throw new RangeError(`Non-finite numeric value "${value}" in ${context}`);
  }
  return n;
}

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of range [${config.min}-${config.max}] in field "${config.name}" (${context})`
    );
  }
}

function expandRange(start: number, end: number, step: number, config: FieldConfig, context: string): number[] {
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in field "${config.name}" (${context})`
    );
  }
  if (step <= 0) {
    throw new RangeError(
      `Step must be a positive integer, got ${step} in field "${config.name}" (${context})`
    );
  }
  assertInRange(start, config, context);
  assertInRange(end, config, context);

  const results: number[] = [];
  for (let i = start; i <= end; i += step) {
    results.push(i);
  }
  return results;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const trimmed = segment.trim();

  if (!trimmed) {
    throw new RangeError(`Empty segment in field "${config.name}"`);
  }

  // Handle step notation: "*/n", "a-b/n", or "a/n" (start from a, step to max)
  const slashIndex = trimmed.indexOf("/");
  if (slashIndex !== -1) {
    const lhs = trimmed.slice(0, slashIndex);
    const rhs = trimmed.slice(slashIndex + 1);

    if (!rhs) {
      throw new RangeError(`Missing step value after "/" in field "${config.name}" ("${trimmed}")`);
    }

    const step = parseIntStrict(rhs, `step of "${trimmed}" in "${config.name}"`);

    if (lhs === "*") {
      return expandRange(config.min, config.max, step, config, trimmed);
    }

    const dashIndex = lhs.indexOf("-");
    if (dashIndex !== -1) {
      const start = parseIntStrict(lhs.slice(0, dashIndex), `range start in "${trimmed}"`);
      const end   = parseIntStrict(lhs.slice(dashIndex + 1), `range end in "${trimmed}"`);
      return expandRange(start, end, step, config, trimmed);
    }

    // "a/n" — start at a, step toward max
    const start = parseIntStrict(lhs, `start value in "${trimmed}"`);
    return expandRange(start, config.max, step, config, trimmed);
  }

  // Wildcard
  if (trimmed === "*") {
    return expandRange(config.min, config.max, 1, config, trimmed);
  }

  // Range: "a-b"
  const dashIndex = trimmed.indexOf("-");
  if (dashIndex !== -1) {
    const start = parseIntStrict(trimmed.slice(0, dashIndex), `range start in field "${config.name}"`);
    const end   = parseIntStrict(trimmed.slice(dashIndex + 1), `range end in field "${config.name}"`);
    return expandRange(start, end, 1, config, trimmed);
  }

  // Plain number
  const value = parseIntStrict(trimmed, `field "${config.name}"`);
  assertInRange(value, config, trimmed);
  return [value];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (!field || !field.trim()) {
    throw new RangeError(`Empty value for field "${config.name}"`);
  }

  const segments = field.split(",");
  if (segments.length === 0) {
    throw new RangeError(`No segments found in field "${config.name}"`);
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    const expanded = parseSegment(segment, config);
    for (const v of expanded) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new RangeError("Cron expression must not be empty");
  }

  // Split on whitespace — guard against tabs, multiple spaces, etc.
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new RangeError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, dayOfMonthRaw, monthRaw, dayOfWeekRaw] = fields;

  return {
    minute:     parseField(minuteRaw,     FIELD_CONFIGS[0]),
    hour:       parseField(hourRaw,       FIELD_CONFIGS[1]),
    dayOfMonth: parseField(dayOfMonthRaw, FIELD_CONFIGS[2]),
    month:      parseField(monthRaw,      FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dayOfWeekRaw,  FIELD_CONFIGS[4]),
  };
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  // Exclude built-in object types that should be treated as leaf values
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function escapeKey(key: string): string {
  // Escape literal dots in keys to prevent ambiguity in dot-notation output
  return key.replace(/\\/g, "\\\\").replace(/\./g, "\\.");
}

function flattenObjectInternal(
  obj: PlainObject,
  prefix: string,
  result: PlainObject,
  visited: WeakSet<object>
): void {
  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Preserve empty objects as explicit leaf values if they have a prefix
    if (prefix !== "") {
      result[prefix] = {};
    }
    return;
  }

  for (const key of keys) {
    // Guard against prototype pollution
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const escapedKey = escapeKey(key);
    const fullKey = prefix !== "" ? `${prefix}.${escapedKey}` : escapedKey;
    const value = (obj as Record<string, unknown>)[key];

    if (isPlainObject(value)) {
      if (visited.has(value)) {
        // Circular reference detected — store a sentinel rather than infinite-looping
        result[fullKey] = "[Circular]";
        continue;
      }
      visited.add(value);
      flattenObjectInternal(value, fullKey, result, visited);
      visited.delete(value);
    } else if (Array.isArray(value)) {
      if (visited.has(value)) {
        result[fullKey] = "[Circular]";
        continue;
      }
      visited.add(value);
      flattenArray(value, fullKey, result, visited);
      visited.delete(value);
    } else {
      // Primitive, Date, RegExp, Function, etc. — treat as leaf
      result[fullKey] = value;
    }
  }
}

function flattenArray(
  arr: unknown[],
  prefix: string,
  result: PlainObject,
  visited: WeakSet<object>
): void {
  if (arr.length === 0) {
    result[prefix] = [];
    return;
  }

  for (let i = 0; i < arr.length; i++) {
    const fullKey = `${prefix}.${i}`;
    const value = arr[i];

    if (isPlainObject(value)) {
      if (visited.has(value)) {
        result[fullKey] = "[Circular]";
        continue;
      }
      visited.add(value);
      flattenObjectInternal(value, fullKey, result, visited);
      visited.delete(value);
    } else if (Array.isArray(value)) {
      if (visited.has(value)) {
        result[fullKey] = "[Circular]";
        continue;
      }
      visited.add(value);
      flattenArray(value, fullKey, result, visited);
      visited.delete(value);
    } else {
      result[fullKey] = value;
    }
  }
}

export default function flattenObject(input: unknown): PlainObject {
  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        Array.isArray(input) ? "array" : typeof input
      }`
    );
  }

  const result: PlainObject = {};
  const visited = new WeakSet<object>();
  visited.add(input);
  flattenObjectInternal(input, "", result, visited);
  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

export interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: Readonly<Record<CronField, FieldConfig>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER: readonly CronField[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
] as const;

function assertInt(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (trimmed === "" || !/^-?\d+$/.test(trimmed)) {
    throw new Error(`Expected integer for ${context}, got "${raw}"`);
  }
  const n = parseInt(trimmed, 10);
  if (!Number.isFinite(n)) {
    throw new Error(`Non-finite integer for ${context}: "${raw}"`);
  }
  return n;
}

function assertInBounds(value: number, config: FieldConfig, label: string): void {
  if (value < config.min || value > config.max) {
    throw new Error(
      `Value ${value} for ${label} is out of valid range [${config.min}, ${config.max}]`
    );
  }
}

function expandRange(start: number, end: number, step: number, config: FieldConfig, label: string): number[] {
  if (start > end) {
    throw new Error(`Range start ${start} exceeds end ${end} in ${label}`);
  }
  assertInBounds(start, config, label);
  assertInBounds(end, config, label);
  if (step < 1) {
    throw new Error(`Step must be >= 1 in ${label}, got ${step}`);
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(token: string, config: FieldConfig, label: string): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new Error(`Empty segment in ${label}`);
  }

  // Step: */N  |  N/N  |  N-M/N
  if (trimmed.includes("/")) {
    const slashIndex = trimmed.lastIndexOf("/");
    const lhs = trimmed.slice(0, slashIndex);
    const rhs = trimmed.slice(slashIndex + 1);

    if (lhs === "" || rhs === "") {
      throw new Error(`Malformed step expression "${trimmed}" in ${label}`);
    }

    const step = assertInt(rhs, `step in ${label}`);
    if (step < 1) {
      throw new Error(`Step value must be >= 1 in ${label}, got ${step}`);
    }

    if (lhs === "*") {
      return expandRange(config.min, config.max, step, config, label);
    }

    if (lhs.includes("-")) {
      const dashParts = lhs.split("-");
      if (dashParts.length !== 2 || dashParts[0].trim() === "" || dashParts[1].trim() === "") {
        throw new Error(`Malformed range "${lhs}" in ${label}`);
      }
      const start = assertInt(dashParts[0], `range start in ${label}`);
      const end = assertInt(dashParts[1], `range end in ${label}`);
      return expandRange(start, end, step, config, label);
    }

    // Single start value: N/step means start at N, step to max
    const start = assertInt(lhs, `step base in ${label}`);
    return expandRange(start, config.max, step, config, label);
  }

  // Wildcard
  if (trimmed === "*") {
    return expandRange(config.min, config.max, 1, config, label);
  }

  // Range: N-M
  if (trimmed.includes("-")) {
    const dashParts = trimmed.split("-");
    if (dashParts.length !== 2 || dashParts[0].trim() === "" || dashParts[1].trim() === "") {
      throw new Error(`Malformed range "${trimmed}" in ${label}`);
    }
    const start = assertInt(dashParts[0], `range start in ${label}`);
    const end = assertInt(dashParts[1], `range end in ${label}`);
    return expandRange(start, end, 1, config, label);
  }

  // Single number
  const value = assertInt(trimmed, label);
  assertInBounds(value, config, label);
  return [value];
}

function parseField(token: string, config: FieldConfig, label: string): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new Error(`Empty field for ${label}`);
  }

  // Comma-separated list — each part may itself be a range or step
  const segments = trimmed.split(",");
  if (segments.length > 1) {
    const valueSet = new Set<number>();
    for (const segment of segments) {
      if (segment.trim() === "") {
        throw new Error(`Empty element in comma-separated list for ${label}`);
      }
      const parsed = parseSegment(segment, config, label);
      parsed.forEach((v) => valueSet.add(v));
    }
    return Array.from(valueSet).sort((a, b) => a - b);
  }

  return parseSegment(trimmed, config, label);
}

export default function parseCron(expression: string): CronResult {
  if (expression === null || expression === undefined) {
    throw new Error("Cron expression must not be null or undefined");
  }
  if (typeof expression !== "string") {
    throw new Error(`Cron expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${trimmed}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const config = FIELD_CONFIGS[fieldName];
    try {
      result[fieldName] = parseField(fields[i], config, fieldName);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid cron field #${i + 1} (${fieldName}) = "${fields[i]}": ${message}`);
    }
  }

  return result;
}

export type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldName = keyof CronResult;

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_ORDER: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

const FIELD_CONFIGS: Record<FieldName, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 0 and 7 are both Sunday in standard cron
};

const INTEGER_RE = /^\d+$/;

function assertInteger(raw: string, context: string): number {
  if (!INTEGER_RE.test(raw)) {
    throw new Error(`Expected an integer in ${context}, got: "${raw}"`);
  }
  const n = parseInt(raw, 10);
  if (!Number.isFinite(n)) {
    throw new Error(`Non-finite integer in ${context}: "${raw}"`);
  }
  return n;
}

function assertInBounds(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} is out of bounds [${config.min}, ${config.max}] in ${context}`
    );
  }
}

function expandRange(start: number, end: number, step: number): number[] {
  if (!Number.isInteger(step) || step <= 0) {
    throw new Error(`Step must be a positive integer, got: ${step}`);
  }
  if (start > end) {
    throw new RangeError(`Range start ${start} must not exceed range end ${end}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parsePart(part: string, field: FieldName, config: FieldConfig): number[] {
  const context = `field "${field}", part "${part}"`;

  // Step expression: <range-or-wildcard>/<step>
  const slashIndex = part.indexOf("/");
  if (slashIndex !== -1) {
    const rangeStr = part.slice(0, slashIndex);
    const stepStr = part.slice(slashIndex + 1);

    if (stepStr === "" || rangeStr === "") {
      throw new Error(`Malformed step expression in ${context}`);
    }

    const step = assertInteger(stepStr, context);
    if (step <= 0) {
      throw new RangeError(`Step must be > 0 in ${context}`);
    }

    let start: number;
    let end: number;

    if (rangeStr === "*") {
      start = config.min;
      end = config.max;
    } else {
      const dashIndex = rangeStr.indexOf("-");
      if (dashIndex === -1) {
        // Single value with step: treat as start..max
        start = assertInteger(rangeStr, context);
        assertInBounds(start, config, context);
        end = config.max;
      } else {
        start = assertInteger(rangeStr.slice(0, dashIndex), context);
        end   = assertInteger(rangeStr.slice(dashIndex + 1), context);
        assertInBounds(start, config, context);
        assertInBounds(end,   config, context);
      }
    }

    return expandRange(start, end, step);
  }

  // Wildcard
  if (part === "*") {
    return expandRange(config.min, config.max, 1);
  }

  // Range: <start>-<end>
  const dashIndex = part.indexOf("-");
  if (dashIndex !== -1) {
    // Guard against negative numbers accidentally parsed as ranges
    const startStr = part.slice(0, dashIndex);
    const endStr   = part.slice(dashIndex + 1);

    if (startStr === "" || endStr === "") {
      throw new Error(`Malformed range in ${context}`);
    }

    const start = assertInteger(startStr, context);
    const end   = assertInteger(endStr,   context);
    assertInBounds(start, config, context);
    assertInBounds(end,   config, context);

    return expandRange(start, end, 1);
  }

  // Single numeric value
  const value = assertInteger(part, context);
  assertInBounds(value, config, context);
  return [value];
}

function parseField(token: string, field: FieldName): number[] {
  if (token === "" || token == null) {
    throw new Error(`Empty token for field "${field}"`);
  }

  const config = FIELD_CONFIGS[field];
  const segments = token.split(",");

  if (segments.length === 0) {
    throw new Error(`No segments found in token "${token}" for field "${field}"`);
  }

  const seen = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new Error(`Empty segment in comma list for field "${field}": "${token}"`);
    }
    for (const value of parsePart(trimmed, field, config)) {
      seen.add(value);
    }
  }

  // Normalise dayOfWeek: treat 7 (alt Sunday) as 0
  if (field === "dayOfWeek" && seen.has(7)) {
    seen.delete(7);
    seen.add(0);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got: ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  // Split on any whitespace run to tolerate extra spaces
  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    result[name] = parseField(fields[i], name);
  }

  return result;
}

type NestedObject = { [key: string]: unknown };
type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flatten(
  obj: NestedObject,
  prefix: string,
  result: FlatObject,
  ancestors: WeakSet<object>
): void {
  if (ancestors.has(obj)) {
    throw new TypeError(
      `Circular reference detected at path: "${prefix || "<root>"}"`
    );
  }

  ancestors.add(obj);

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      flatten(value, flatKey, result, ancestors);
    } else {
      // Leaf: primitives, arrays, Dates, RegExps, null, undefined, empty objects, etc.
      result[flatKey] = value;
    }
  }

  // Backtrack so the same object reference can legitimately appear
  // in sibling branches without triggering a false circular-reference error.
  ancestors.delete(obj);
}

export default function flattenObject(obj: NestedObject): FlatObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: FlatObject = {};
  flatten(obj, "", result, new WeakSet());
  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix = "",
  result: FlattenedObject = {},
  depth = 0,
  maxDepth = 100,
  seen = new WeakSet<object>()
): FlattenedObject {
  if (depth > maxDepth) {
    throw new RangeError(
      `Maximum flattening depth of ${maxDepth} exceeded — possible circular structure or excessively nested input`
    );
  }

  if (!isPlainObject(input) && !Array.isArray(input)) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  const obj = input as Record<string | number, unknown>;

  if (seen.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key "${prefix}"`
    );
  }
  seen.add(obj);

  const entries = Array.isArray(input)
    ? (input as unknown[]).map((v, i) => [String(i), v] as const)
    : Object.entries(obj);

  if (entries.length === 0) {
    if (prefix !== "") {
      result[prefix] = Array.isArray(input) ? (input as unknown as Primitive) : (input as unknown as Primitive);
    }
    seen.delete(obj);
    return result;
  }

  for (const [key, value] of entries) {
    if (typeof key !== "string" && typeof key !== "number") continue;

    const safeKey = String(key);
    if (safeKey === "" || safeKey === "__proto__" || safeKey === "constructor" || safeKey === "prototype") {
      continue;
    }

    const nextPrefix = prefix === "" ? safeKey : `${prefix}.${safeKey}`;

    if (isPlainObject(value) || Array.isArray(value)) {
      const nested = value as Record<string | number, unknown>;
      if (seen.has(nested)) {
        throw new TypeError(`Circular reference detected at key "${nextPrefix}"`);
      }
      const nestedEntries = Array.isArray(value)
        ? (value as unknown[]).map((v, i) => [String(i), v] as const)
        : Object.entries(nested);

      if (nestedEntries.length === 0) {
        result[nextPrefix] = Array.isArray(value)
          ? (value as unknown as Primitive)
          : (value as unknown as Primitive);
      } else {
        flattenObject(value, nextPrefix, result, depth + 1, maxDepth, seen);
      }
    } else {
      result[nextPrefix] = value as Primitive;
    }
  }

  seen.delete(obj);
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type NestedObject = {
  [key: string]: Primitive | NestedObject | unknown[] | unknown;
};

type FlattenedObject = Record<string, Primitive | unknown[]>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: {
    delimiter?: string;
    maxDepth?: number;
    preserveArrays?: boolean;
  } = {}
): FlattenedObject {
  const {
    delimiter = ".",
    maxDepth = 100,
    preserveArrays = true,
  } = options;

  if (typeof delimiter !== "string" || delimiter.length === 0) {
    throw new TypeError("delimiter must be a non-empty string");
  }

  if (!Number.isInteger(maxDepth) || maxDepth < 1) {
    throw new RangeError("maxDepth must be a positive integer");
  }

  if (input === null || input === undefined) {
    return {};
  }

  if (!isPlainObject(input)) {
    throw new TypeError("input must be a plain object, null, or undefined");
  }

  const result: FlattenedObject = {};
  const seen = new WeakSet<object>();

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (isPlainObject(current)) {
      if (seen.has(current as object)) {
        throw new Error(
          `Circular reference detected at key "${prefix}"`
        );
      }

      seen.add(current as object);

      const keys = Object.keys(current as NestedObject);

      if (keys.length === 0) {
        // Empty object — preserve as value only if it's a nested key
        if (prefix !== "") {
          (result as Record<string, unknown>)[prefix] = {};
        }
        seen.delete(current as object);
        return;
      }

      if (depth >= maxDepth) {
        // At max depth, store whatever remains as-is
        if (prefix !== "") {
          (result as Record<string, unknown>)[prefix] = current;
        }
        seen.delete(current as object);
        return;
      }

      for (const key of keys) {
        if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

        // Guard against keys that contain the delimiter, which would produce
        // ambiguous paths. We allow it but the consumer is warned implicitly
        // by the structure being unambiguous only in one direction.
        const newKey = prefix === "" ? key : `${prefix}${delimiter}${key}`;
        recurse((current as NestedObject)[key], newKey, depth + 1);
      }

      seen.delete(current as object);
    } else if (Array.isArray(current)) {
      if (preserveArrays) {
        (result as Record<string, unknown>)[prefix] = current;
      } else {
        if (current.length === 0) {
          (result as Record<string, unknown>)[prefix] = current;
          return;
        }
        for (let i = 0; i < current.length; i++) {
          const newKey = prefix === "" ? String(i) : `${prefix}${delimiter}${i}`;
          recurse(current[i], newKey, depth + 1);
        }
      }
    } else {
      // Primitive or unrecognised value — store as-is
      (result as Record<string, unknown>)[prefix] = current;
    }
  }

  recurse(input, "", 0);

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  maxDepth: number = 100
): FlatObject {
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : Array.isArray(input) ? "array" : typeof input
      }`
    );
  }

  const result: FlatObject = {};

  function recurse(current: unknown, prefix: string, depth: number): void {
    if (depth > maxDepth) {
      throw new RangeError(
        `flattenObject exceeded maximum depth of ${maxDepth}. Possible circular reference or deeply nested structure.`
      );
    }

    if (isPlainObject(current)) {
      const keys = Object.keys(current);

      if (keys.length === 0) {
        // Preserve empty objects as a value
        if (prefix) {
          (result as Record<string, unknown>)[prefix] = {};
        }
        return;
      }

      for (const key of keys) {
        if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

        const value = (current as Record<string, unknown>)[key];
        const newKey = prefix ? `${prefix}.${key}` : key;

        if (isPlainObject(value)) {
          recurse(value, newKey, depth + 1);
        } else {
          (result as Record<string, unknown>)[newKey] = value;
        }
      }
    }
  }

  recurse(input, "", 0);
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  maxDepth: number = 100
): FlattenedObject {
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : Array.isArray(input) ? "array" : typeof input
      }`
    );
  }

  const result: FlattenedObject = {};

  function recurse(
    current: Record<string, unknown>,
    prefix: string,
    depth: number
  ): void {
    if (depth > maxDepth) {
      throw new RangeError(
        `flattenObject exceeded maximum depth of ${maxDepth}. Possible circular reference or deeply nested structure.`
      );
    }

    for (const key of Object.keys(current)) {
      if (!Object.prototype.hasOwnProperty.call(current, key)) continue;

      const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
      const value = current[key];

      if (isPlainObject(value)) {
        const nested = value as Record<string, unknown>;
        if (Object.keys(nested).length === 0) {
          // Preserve empty objects as-is by storing undefined or skipping;
          // here we store the empty object marker as an empty key indicator.
          // Conventional choice: omit empty objects from flattened output.
          continue;
        }
        recurse(nested, fullKey, depth + 1);
      } else {
        result[fullKey] = value as Primitive;
      }
    }
  }

  recurse(input, "", 0);

  return result;
}

export default flattenObject;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: Readonly<Record<FieldName, FieldConfig>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER: ReadonlyArray<FieldName> = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

// Only digits, nothing else — guards against floats, negatives, hex, etc.
const DIGITS_ONLY = /^\d+$/;

function assertPositiveInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!DIGITS_ONLY.test(trimmed)) {
    throw new Error(
      `Invalid numeric token "${trimmed}" in ${context}: expected a non-negative integer`
    );
  }
  const n = Number(trimmed);
  if (!Number.isFinite(n) || !Number.isInteger(n)) {
    throw new Error(`Numeric overflow or invalid integer "${trimmed}" in ${context}`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of the allowed range [${min}, ${max}] in ${context}`
    );
  }
}

function expandValues(
  start: number,
  end: number,
  step: number,
  { min, max }: FieldConfig,
  context: string
): number[] {
  if (step < 1) {
    throw new RangeError(`Step value must be >= 1, got ${step} in ${context}`);
  }
  assertInRange(start, min, max, context);
  assertInRange(end, min, max, context);
  if (start > end) {
    throw new RangeError(
      `Range start ${start} must be <= range end ${end} in ${context}`
    );
  }

  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(v);
  }
  return values;
}

// Matches an optional "base/step" suffix; base may be "*" or "N-M"
const STEP_RE = /^(.+)\/(\d+)$/;
const RANGE_RE = /^(\d+)-(\d+)$/;

function parseSegment(
  raw: string,
  config: FieldConfig,
  context: string
): number[] {
  const { min, max } = config;

  // ── Step expression: */N  or  start-end/N ──────────────────────────────────
  const stepMatch = STEP_RE.exec(raw);
  if (stepMatch !== null) {
    const [, base, stepRaw] = stepMatch as [string, string, string];

    if (!DIGITS_ONLY.test(stepRaw)) {
      throw new Error(`Invalid step value "${stepRaw}" in ${context}`);
    }
    const step = Number(stepRaw);
    if (step < 1) {
      throw new RangeError(`Step must be >= 1, got ${step} in ${context}`);
    }

    if (base === "*") {
      return expandValues(min, max, step, config, context);
    }

    const rangeStepMatch = RANGE_RE.exec(base);
    if (rangeStepMatch !== null) {
      const start = assertPositiveInteger(rangeStepMatch[1], context);
      const end   = assertPositiveInteger(rangeStepMatch[2], context);
      return expandValues(start, end, step, config, context);
    }

    throw new Error(
      `Unsupported step base expression "${base}" in ${context}; expected "*" or "N-M"`
    );
  }

  // ── Wildcard ───────────────────────────────────────────────────────────────
  if (raw === "*") {
    return expandValues(min, max, 1, config, context);
  }

  // ── Range: N-M ─────────────────────────────────────────────────────────────
  const rangeMatch = RANGE_RE.exec(raw);
  if (rangeMatch !== null) {
    const start = assertPositiveInteger(rangeMatch[1], context);
    const end   = assertPositiveInteger(rangeMatch[2], context);
    return expandValues(start, end, 1, config, context);
  }

  // ── Single number ──────────────────────────────────────────────────────────
  if (DIGITS_ONLY.test(raw)) {
    const n = assertPositiveInteger(raw, context);
    assertInRange(n, min, max, context);
    return [n];
  }

  throw new Error(
    `Unrecognised cron segment "${raw}" in ${context}; ` +
    `expected *, N, N-M, */N, N-M/N, or a comma-separated combination`
  );
}

function parseField(
  raw: string,
  config: FieldConfig,
  fieldName: string
): number[] {
  const context = `field "${fieldName}"`;

  if (typeof raw !== "string") {
    throw new TypeError(`Expected a string for ${context}, got ${typeof raw}`);
  }

  const trimmed = raw.trim();
  if (trimmed.length === 0) {
    throw new Error(`Empty value for ${context}`);
  }

  const parts = trimmed.split(",");
  const seen = new Set<number>();

  for (const part of parts) {
    const segment = part.trim();
    if (segment.length === 0) {
      throw new Error(
        `Empty segment in comma-separated list for ${context}; ` +
        `check for leading, trailing, or consecutive commas`
      );
    }
    for (const v of parseSegment(segment, config, context)) {
      seen.add(v);
    }
  }

  if (seen.size === 0) {
    throw new Error(`Parsed zero valid values for ${context}; this is a bug`);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (expression === null || expression === undefined) {
    throw new TypeError("parseCron: expression must be a non-null string");
  }
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron: expected a string, got ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new Error("parseCron: expression must not be empty or whitespace-only");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `parseCron: expression must have exactly 5 whitespace-separated fields ` +
      `(minute hour dayOfMonth month dayOfWeek), got ${fields.length}`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    result[name] = parseField(fields[i], FIELD_CONFIGS[name], name);
  }

  return result;
}
